window.__SEA_SPECIES_META__ = {"red-maple": {"name": "Red maple", "cat": "tree", "group": "maple tree", "hab": "deciduous forests", "habKey": "decid", "diet": "(makes its own food from sunlight)", "art": "oak", "trait": "Its leaves flush brilliant red in autumn, and even its twigs, buds and winged seeds carry a reddish tint."}, "sugar-maple": {"name": "Sugar maple", "cat": "tree", "group": "maple tree", "hab": "deciduous forests", "habKey": "decid", "diet": "(makes its own food from sunlight)", "art": "oak", "trait": "Its sweet sap is boiled down to make maple syrup, and its leaf is the model for Canada's flag."}, "white-oak": {"name": "White oak", "cat": "tree", "group": "oak tree", "hab": "deciduous forests", "habKey": "decid", "diet": "(makes its own food from sunlight)", "art": "oak", "trait": "Its rounded leaf lobes and sweeter acorns set it apart from sharp-lobed red oaks, and it can live more than 300 years."}, "northern-red-oak": {"name": "Northern red oak", "cat": "tree", "group": "oak tree", "hab": "deciduous forests", "habKey": "decid", "diet": "(makes its own food from sunlight)", "art": "oak", "trait": "Its leaves have pointed, bristle-tipped lobes, and its bitter acorns take two years to ripen."}, "eastern-white-pine": {"name": "Eastern white pine", "cat": "tree", "group": "pine tree", "hab": "coniferous forests", "habKey": "conifer", "diet": "(makes its own food from sunlight)", "art": "mountain", "trait": "Its soft needles grow in bundles of five, one for each letter in the word 'white'."}, "loblolly-pine": {"name": "Loblolly pine", "cat": "tree", "group": "pine tree", "hab": "coniferous forests", "habKey": "conifer", "diet": "(makes its own food from sunlight)", "art": "mountain", "trait": "A fast-growing southern pine, it is the most planted timber tree in the United States."}, "douglas-fir": {"name": "Douglas-fir", "cat": "tree", "group": "conifer tree", "hab": "coniferous forests", "habKey": "conifer", "diet": "(makes its own food from sunlight)", "art": "mountain", "trait": "Despite its name it is not a true fir; its cones have three-pronged bracts that poke out like tiny mouse tails."}, "coast-redwood": {"name": "Coast redwood", "cat": "tree", "group": "redwood tree", "hab": "moist shady forests", "habKey": "wetforest", "diet": "(makes its own food from sunlight)", "art": "oak", "trait": "It is the tallest living thing on Earth, with record individuals topping 115 meters."}, "giant-sequoia": {"name": "Giant sequoia", "cat": "tree", "group": "sequoia tree", "hab": "mountains and high slopes", "habKey": "mountain", "diet": "(makes its own food from sunlight)", "art": "mountain", "trait": "By volume it is the largest single living thing on Earth, and its thick spongy bark helps it survive forest fires."}, "quaking-aspen": {"name": "Quaking aspen", "cat": "tree", "group": "aspen tree", "hab": "mountains and high slopes", "habKey": "mountain", "diet": "(makes its own food from sunlight)", "art": "mountain", "trait": "Its flat leaf-stems make the leaves tremble in the lightest breeze, and a whole grove can be one connected organism."}, "paper-birch": {"name": "Paper birch", "cat": "tree", "group": "birch tree", "hab": "coniferous forests", "habKey": "conifer", "diet": "(makes its own food from sunlight)", "art": "mountain", "trait": "Its white bark peels in papery strips and was traditionally used to build canoes."}, "eastern-hemlock": {"name": "Eastern hemlock", "cat": "tree", "group": "conifer tree", "hab": "moist shady forests", "habKey": "wetforest", "diet": "(makes its own food from sunlight)", "art": "oak", "trait": "A shade-loving evergreen of cool ravines, it is being killed across the East by a tiny invasive insect, the hemlock woolly adelgid."}, "american-sycamore": {"name": "American sycamore", "cat": "tree", "group": "sycamore tree", "hab": "streamsides and riverbanks", "habKey": "riparian", "diet": "(makes its own food from sunlight)", "art": "oak", "trait": "Its mottled bark flakes off to reveal smooth white patches, making streamside trees easy to spot in winter."}, "shagbark-hickory": {"name": "Shagbark hickory", "cat": "tree", "group": "hickory tree", "hab": "deciduous forests", "habKey": "decid", "diet": "(makes its own food from sunlight)", "art": "oak", "trait": "Its gray bark peels away in long, shaggy strips, and its sweet nuts feed many woodland animals."}, "american-beech": {"name": "American beech", "cat": "tree", "group": "beech tree", "hab": "deciduous forests", "habKey": "decid", "diet": "(makes its own food from sunlight)", "art": "oak", "trait": "Its smooth silver-gray bark holds onto pale, dry leaves through winter, and it produces triangular beechnuts."}, "bald-cypress": {"name": "Bald cypress", "cat": "tree", "group": "cypress tree", "hab": "wetlands and marshes", "habKey": "wetland", "diet": "(makes its own food from sunlight)", "art": "oak", "trait": "A swamp conifer that drops its needles in winter, it grows woody 'knees' that poke up from the water around its base."}, "joshua-tree": {"name": "Joshua tree", "cat": "tree", "group": "tree (a giant yucca)", "hab": "deserts and dry scrub", "habKey": "desert", "diet": "(makes its own food from sunlight)", "art": "oak", "trait": "This spiky Mojave Desert icon is not a true tree but a giant yucca, and it is pollinated only by the yucca moth."}, "saguaro": {"name": "Saguaro", "cat": "tree", "group": "giant cactus tree", "hab": "deserts and dry scrub", "habKey": "desert", "diet": "(makes its own food from sunlight)", "art": "oak", "trait": "A giant Sonoran Desert cactus, it can live 150 to 200 years and may not grow its first arm until it is about 70."}, "honey-mesquite": {"name": "Honey mesquite", "cat": "tree", "group": "desert tree", "hab": "deserts and dry scrub", "habKey": "desert", "diet": "(makes its own food from sunlight)", "art": "oak", "trait": "Its roots can reach far underground to find water, among the deepest roots known of any plant."}, "live-oak": {"name": "Southern live oak", "cat": "tree", "group": "oak tree", "hab": "coastal dunes and shores", "habKey": "coastal", "diet": "(makes its own food from sunlight)", "art": "coast", "trait": "An evergreen oak with wide, spreading limbs, it is often draped in Spanish moss across the Deep South."}, "big-sagebrush": {"name": "Big sagebrush", "cat": "shrub", "group": "desert shrub", "hab": "deserts and dry scrub", "habKey": "desert", "diet": "(makes its own food from sunlight)", "art": "forest", "trait": "Its silvery, three-toothed leaves give the Western range its sharp scent, and it shelters the imperiled sage-grouse."}, "serviceberry": {"name": "Serviceberry", "cat": "shrub", "group": "shrub", "hab": "forest edges and clearings", "habKey": "edge", "diet": "(makes its own food from sunlight)", "art": "forest", "trait": "Its early white spring blossoms and sweet summer berries feed birds, bears and people alike."}, "highbush-blueberry": {"name": "Highbush blueberry", "cat": "shrub", "group": "shrub", "hab": "wetlands and marshes", "habKey": "wetland", "diet": "(makes its own food from sunlight)", "art": "forest", "trait": "The wild ancestor of cultivated blueberries, it needs acidic soil and turns fiery red in fall."}, "common-milkweed": {"name": "Common milkweed", "cat": "wildflower", "group": "wildflower", "hab": "meadows and open fields", "habKey": "meadow", "diet": "(makes its own food from sunlight)", "art": "meadow", "trait": "Its leaves are the only food monarch caterpillars can eat, and its pods release silky, parachute-borne seeds."}, "black-eyed-susan": {"name": "Black-eyed Susan", "cat": "wildflower", "group": "wildflower", "hab": "meadows and open fields", "habKey": "meadow", "diet": "(makes its own food from sunlight)", "art": "meadow", "trait": "Its golden petals ring a dark brown center, a cheerful prairie bloom that turns to follow the sun when young."}, "purple-coneflower": {"name": "Purple coneflower", "cat": "wildflower", "group": "wildflower", "hab": "grasslands and prairies", "habKey": "grass", "diet": "(makes its own food from sunlight)", "art": "meadow", "trait": "Its drooping purple petals surround a spiky orange cone, and it is widely grown both for beauty and as the herb echinacea."}, "california-poppy": {"name": "California poppy", "cat": "wildflower", "group": "wildflower", "hab": "deserts and dry scrub", "habKey": "desert", "diet": "(makes its own food from sunlight)", "art": "wildflower", "trait": "California's state flower, its orange petals close up at night and on cloudy days."}, "fireweed": {"name": "Fireweed", "cat": "wildflower", "group": "wildflower", "hab": "mountains and high slopes", "habKey": "mountain", "diet": "(makes its own food from sunlight)", "art": "wildflower", "trait": "It is named because it is one of the first plants to bloom on burned ground, painting recovering land bright pink."}, "texas-bluebonnet": {"name": "Texas bluebonnet", "cat": "wildflower", "group": "wildflower", "hab": "grasslands and prairies", "habKey": "grass", "diet": "(makes its own food from sunlight)", "art": "meadow", "trait": "The state flower of Texas, it blankets spring roadsides in deep blue and, as a legume, enriches the soil with nitrogen."}, "white-trillium": {"name": "White trillium", "cat": "wildflower", "group": "wildflower", "hab": "moist shady forests", "habKey": "wetforest", "diet": "(makes its own food from sunlight)", "art": "wildflower", "trait": "Its parts come in threes, three leaves and three petals, and picking the flower can kill the whole plant."}, "cardinal-flower": {"name": "Cardinal flower", "cat": "wildflower", "group": "wildflower", "hab": "wetlands and marshes", "habKey": "wetland", "diet": "(makes its own food from sunlight)", "art": "wildflower", "trait": "Its brilliant red tubular blooms are shaped for hummingbirds, whose long bills can reach the hidden nectar."}, "goldenrod": {"name": "Goldenrod", "cat": "wildflower", "group": "wildflower", "hab": "meadows and open fields", "habKey": "meadow", "diet": "(makes its own food from sunlight)", "art": "meadow", "trait": "Its plumes of tiny yellow flowers feed late-season pollinators, and despite the myth it does not cause hay fever."}, "big-bluestem": {"name": "Big bluestem", "cat": "grass", "group": "tallgrass", "hab": "grasslands and prairies", "habKey": "grass", "diet": "(makes its own food from sunlight)", "art": "meadow", "trait": "The signature grass of the tallgrass prairie, it can grow over two meters tall with roots reaching nearly as deep."}, "switchgrass": {"name": "Switchgrass", "cat": "grass", "group": "prairie grass", "hab": "grasslands and prairies", "habKey": "grass", "diet": "(makes its own food from sunlight)", "art": "meadow", "trait": "A tough native prairie grass with deep roots, it is studied as a renewable source of biofuel."}, "little-bluestem": {"name": "Little bluestem", "cat": "grass", "group": "prairie grass", "hab": "grasslands and prairies", "habKey": "grass", "diet": "(makes its own food from sunlight)", "art": "meadow", "trait": "Its blue-green summer stems turn coppery red in fall, coloring prairies through the winter."}, "broadleaf-cattail": {"name": "Broadleaf cattail", "cat": "grass", "group": "wetland reed", "hab": "wetlands and marshes", "habKey": "wetland", "diet": "(makes its own food from sunlight)", "art": "grassland", "trait": "Its brown sausage-shaped flower spikes release thousands of fluffy seeds, and nearly every part of it is edible."}, "cinnamon-fern": {"name": "Cinnamon fern", "cat": "fern or moss", "group": "fern", "hab": "wetlands and marshes", "habKey": "wetland", "diet": "(makes its own food from sunlight)", "art": "fern", "trait": "It is named for the cinnamon-colored fertile fronds that stand upright in the center of the plant."}, "ostrich-fern": {"name": "Ostrich fern", "cat": "fern or moss", "group": "fern", "hab": "moist shady forests", "habKey": "wetforest", "diet": "(makes its own food from sunlight)", "art": "fern", "trait": "Its young, tightly coiled fronds, called fiddleheads, are foraged and eaten as a spring vegetable."}, "bracken-fern": {"name": "Bracken fern", "cat": "fern or moss", "group": "fern", "hab": "forests and woodlands", "habKey": "forest", "diet": "(makes its own food from sunlight)", "art": "fern", "trait": "One of the world's most widespread ferns, it spreads aggressively across ground that has been burned or cleared."}, "sphagnum-moss": {"name": "Sphagnum moss", "cat": "fern or moss", "group": "moss", "hab": "wetlands and marshes", "habKey": "wetland", "diet": "(makes its own food from sunlight)", "art": "fern", "trait": "This bog moss can soak up many times its own weight in water and slowly builds peat over centuries."}, "yellow-morel": {"name": "Yellow morel", "cat": "fungus or lichen", "group": "mushroom (fungus)", "hab": "moist shady forests", "habKey": "wetforest", "diet": "(feeds on dead matter)", "art": "mushroom", "trait": "Its honeycomb-pitted cap makes it a prized spring edible, but only when an expert tells it apart from toxic look-alikes."}, "chanterelle": {"name": "Golden chanterelle", "cat": "fungus or lichen", "group": "mushroom (fungus)", "hab": "forests and woodlands", "habKey": "forest", "diet": "", "art": "mushroom", "trait": "A golden, funnel-shaped edible with a faint apricot smell, it grows in a partnership with the roots of trees."}, "fly-agaric": {"name": "Fly agaric", "cat": "fungus or lichen", "group": "mushroom (fungus)", "hab": "coniferous forests", "habKey": "conifer", "diet": "", "art": "mushroom", "trait": "Its iconic red cap dotted with white is famous in fairy tales, and it is toxic and should never be eaten."}, "oyster-mushroom": {"name": "Oyster mushroom", "cat": "fungus or lichen", "group": "shelf fungus", "hab": "forests and woodlands", "habKey": "forest", "diet": "(feeds on dead matter)", "art": "mushroom", "trait": "It grows in shelving clusters on dead wood and is one of the few fungi that can trap and digest tiny roundworms for nitrogen."}, "turkey-tail": {"name": "Turkey tail", "cat": "fungus or lichen", "group": "bracket fungus", "hab": "forests and woodlands", "habKey": "forest", "diet": "(feeds on dead matter)", "art": "mushroom", "trait": "Its banded, fan-shaped brackets help rot fallen logs, returning their nutrients to the forest floor."}, "shaggy-mane": {"name": "Shaggy mane", "cat": "fungus or lichen", "group": "mushroom (fungus)", "hab": "towns, parks and gardens", "habKey": "urban", "diet": "(feeds on dead matter)", "art": "mushroom", "trait": "As it ages, its tall white shaggy cap dissolves into an inky black liquid to release its spores."}, "british-soldiers": {"name": "British soldiers lichen", "cat": "fungus or lichen", "group": "lichen", "hab": "rocky outcrops and talus", "habKey": "rocky", "diet": "(makes its own food from sunlight)", "art": "mushroom", "trait": "This tiny lichen is tipped with bright red caps, and like all lichens it is a partnership of a fungus and an alga."}, "reindeer-lichen": {"name": "Reindeer lichen", "cat": "fungus or lichen", "group": "lichen", "hab": "cold northern tundra", "habKey": "tundra", "diet": "(makes its own food from sunlight)", "art": "tundra", "trait": "A pale, spongy, branching lichen that carpets the far north, it is a winter mainstay for caribou."}, "american-black-bear": {"name": "American black bear", "cat": "mammal", "group": "bear (mammal)", "hab": "forests and woodlands", "habKey": "forest", "diet": "a wide range of plant and animal foods", "art": "fox", "trait": "The most common bear in North America, it climbs trees well and sleeps away the winter in a den."}, "grizzly-bear": {"name": "Grizzly bear", "cat": "mammal", "group": "bear (mammal)", "hab": "mountains and high slopes", "habKey": "mountain", "diet": "a wide range of plant and animal foods", "art": "deer", "trait": "A brown bear of the West, it has a shoulder hump of muscle for digging and can run faster than 50 km/h despite its bulk."}, "gray-wolf": {"name": "Gray wolf", "cat": "mammal", "group": "wolf (mammal)", "hab": "forests and woodlands", "habKey": "forest", "diet": "animals it hunts", "art": "fox", "trait": "It hunts in family packs led by a breeding pair and communicates across long distances by howling."}, "coyote": {"name": "Coyote", "cat": "mammal", "group": "wild dog (mammal)", "hab": "many habitats across North America", "habKey": "widespread", "diet": "a wide range of plant and animal foods", "art": "fox", "trait": "Adaptable enough to thrive even in big cities, its yipping howls are a familiar night sound across the continent."}, "red-fox": {"name": "Red fox", "cat": "mammal", "group": "fox (mammal)", "hab": "forest edges and clearings", "habKey": "edge", "diet": "a wide range of plant and animal foods", "art": "fox", "trait": "It hunts by leaping high to pounce straight down on mice, and can hear a mouse moving under the snow."}, "white-tailed-deer": {"name": "White-tailed deer", "cat": "mammal", "group": "deer (mammal)", "hab": "forest edges and clearings", "habKey": "edge", "diet": "leaves, twigs and buds", "art": "fox", "trait": "When alarmed it raises its white tail like a flag to warn the herd as it bounds away."}, "elk": {"name": "Elk", "cat": "mammal", "group": "deer (mammal)", "hab": "mountains and high slopes", "habKey": "mountain", "diet": "grasses", "art": "deer", "trait": "Among the largest deer, bulls grow huge antlers each year and bugle loudly to rivals during the fall rut."}, "moose": {"name": "Moose", "cat": "mammal", "group": "deer (mammal)", "hab": "wetlands and marshes", "habKey": "wetland", "diet": "leaves, twigs and buds", "art": "beaver", "trait": "The largest deer on Earth, it wades into ponds to feed on water plants and can even dive several meters down."}, "american-bison": {"name": "American bison", "cat": "mammal", "group": "bison (mammal)", "hab": "grasslands and prairies", "habKey": "grass", "diet": "grasses", "art": "fox", "trait": "The largest land animal in North America, it once roamed the plains in the tens of millions before being hunted to near extinction."}, "pronghorn": {"name": "Pronghorn", "cat": "mammal", "group": "hoofed mammal", "hab": "grasslands and prairies", "habKey": "grass", "diet": "grasses", "art": "fox", "trait": "The fastest land animal in North America, it can sprint over 80 km/h and spot predators kilometers away."}, "bighorn-sheep": {"name": "Bighorn sheep", "cat": "mammal", "group": "wild sheep (mammal)", "hab": "mountains and high slopes", "habKey": "mountain", "diet": "grasses", "art": "deer", "trait": "Rams crash their massive curled horns together in head-butting duels that echo across the cliffs."}, "mountain-lion": {"name": "Mountain lion", "cat": "mammal", "group": "wild cat (mammal)", "hab": "mountains and high slopes", "habKey": "mountain", "diet": "animals it hunts", "art": "deer", "trait": "Also called puma or cougar, it can leap the length of a school bus and is the most widely spread wild mammal in the Americas."}, "bobcat": {"name": "Bobcat", "cat": "mammal", "group": "wild cat (mammal)", "hab": "forests and woodlands", "habKey": "forest", "diet": "animals it hunts", "art": "fox", "trait": "Named for its short, 'bobbed' tail, this secretive cat is about twice the size of a house cat and an expert ambush hunter."}, "raccoon": {"name": "Raccoon", "cat": "mammal", "group": "mammal", "hab": "towns, parks and gardens", "habKey": "urban", "diet": "a wide range of plant and animal foods", "art": "fox", "trait": "Its nimble, sensitive front paws can open latches and unwrap food, and its dark mask may cut glare to sharpen its night vision."}, "striped-skunk": {"name": "Striped skunk", "cat": "mammal", "group": "mammal", "hab": "forest edges and clearings", "habKey": "edge", "diet": "a wide range of plant and animal foods", "art": "fox", "trait": "When threatened it can spray a foul-smelling musk accurately several meters at an attacker's face."}, "north-american-beaver": {"name": "North American beaver", "cat": "mammal", "group": "rodent (mammal)", "hab": "rivers and streams", "habKey": "river", "diet": "plants, leaves and shoots", "art": "beaver", "trait": "The continent's largest rodent, it fells trees with chisel-like teeth and builds dams that create whole wetlands."}, "river-otter": {"name": "North American river otter", "cat": "mammal", "group": "mammal", "hab": "rivers and streams", "habKey": "river", "diet": "fish and other water animals", "art": "beaver", "trait": "A playful swimmer with dense, water-repellent fur, it can hold its breath for several minutes while chasing fish."}, "eastern-gray-squirrel": {"name": "Eastern gray squirrel", "cat": "mammal", "group": "rodent (mammal)", "hab": "towns, parks and gardens", "habKey": "urban", "diet": "seeds and nuts", "art": "fox", "trait": "It buries thousands of nuts each fall and relocates many later by memory and smell, planting forests it forgets about."}, "american-red-squirrel": {"name": "American red squirrel", "cat": "mammal", "group": "rodent (mammal)", "hab": "coniferous forests", "habKey": "conifer", "diet": "seeds and nuts", "art": "fox", "trait": "It loudly defends a small territory and stockpiles pine cones in big larders called middens."}, "eastern-chipmunk": {"name": "Eastern chipmunk", "cat": "mammal", "group": "rodent (mammal)", "hab": "forests and woodlands", "habKey": "forest", "diet": "seeds and nuts", "art": "fox", "trait": "It stuffs food into stretchy cheek pouches and carries it back to an underground burrow with many chambers."}, "porcupine": {"name": "North American porcupine", "cat": "mammal", "group": "rodent (mammal)", "hab": "forests and woodlands", "habKey": "forest", "diet": "leaves, twigs and buds", "art": "fox", "trait": "It is covered in about 30,000 barbed quills that lodge in a predator's skin, though it cannot actually throw them."}, "american-pika": {"name": "American pika", "cat": "mammal", "group": "mammal", "hab": "mountains and high slopes", "habKey": "mountain", "diet": "plants, leaves and shoots", "art": "deer", "trait": "A small relative of rabbits, it gathers 'haystacks' of dried plants to survive winter on cold mountain rockslides."}, "eastern-cottontail": {"name": "Eastern cottontail", "cat": "mammal", "group": "rabbit (mammal)", "hab": "meadows and open fields", "habKey": "meadow", "diet": "plants, leaves and shoots", "art": "fox", "trait": "It freezes to hide, then bursts into a zigzag run, and can raise several litters of young in one year."}, "nine-banded-armadillo": {"name": "Nine-banded armadillo", "cat": "mammal", "group": "mammal", "hab": "forest edges and clearings", "habKey": "edge", "diet": "insects and other small invertebrates", "art": "fox", "trait": "Protected by a bony shell, it almost always gives birth to four identical quadruplets from a single egg."}, "virginia-opossum": {"name": "Virginia opossum", "cat": "mammal", "group": "marsupial (mammal)", "hab": "forest edges and clearings", "habKey": "edge", "diet": "a wide range of plant and animal foods", "art": "fox", "trait": "North America's only marsupial, it carries its young in a pouch and 'plays possum,' faking death, when scared."}, "little-brown-bat": {"name": "Little brown bat", "cat": "mammal", "group": "bat (mammal)", "hab": "caves and rocky crevices", "habKey": "cave", "diet": "insects and other small invertebrates", "art": "cave", "trait": "It hunts insects in the dark using echolocation and can snap up hundreds of mosquito-sized insects in a single hour."}, "bald-eagle": {"name": "Bald eagle", "cat": "bird", "group": "raptor (bird)", "hab": "rivers and streams", "habKey": "river", "diet": "fish and other water animals", "art": "wetland", "trait": "The national bird of the U.S., it builds the largest tree nest of any North American bird, reused and enlarged for years."}, "golden-eagle": {"name": "Golden eagle", "cat": "bird", "group": "raptor (bird)", "hab": "mountains and high slopes", "habKey": "mountain", "diet": "animals it hunts", "art": "bird", "trait": "A powerful hunter of open country, it can dive at more than 240 km/h to seize rabbits and other prey."}, "red-tailed-hawk": {"name": "Red-tailed hawk", "cat": "bird", "group": "raptor (bird)", "hab": "forest edges and clearings", "habKey": "edge", "diet": "animals it hunts", "art": "bird", "trait": "Its rusty-red tail and piercing scream are so iconic that its cry is often dubbed over other birds in movies."}, "osprey": {"name": "Osprey", "cat": "bird", "group": "raptor (bird)", "hab": "rivers and streams", "habKey": "river", "diet": "fish and other water animals", "art": "wetland", "trait": "Built to catch fish, it has a reversible outer toe and barbed foot pads to grip slippery prey snatched from the water."}, "great-horned-owl": {"name": "Great horned owl", "cat": "bird", "group": "owl (bird)", "hab": "forests and woodlands", "habKey": "forest", "diet": "animals it hunts", "art": "bird", "trait": "A fierce nighttime hunter with feather 'horns,' its soft-edged feathers let it fly almost silently."}, "barred-owl": {"name": "Barred owl", "cat": "bird", "group": "owl (bird)", "hab": "moist shady forests", "habKey": "wetforest", "diet": "animals it hunts", "art": "bird", "trait": "Its hooting call sounds like the question 'who cooks for you?' echoing through swampy woods at night."}, "wild-turkey": {"name": "Wild turkey", "cat": "bird", "group": "game bird", "hab": "forests and woodlands", "habKey": "forest", "diet": "a wide range of plant and animal foods", "art": "bird", "trait": "Nearly wiped out by 1900, it has rebounded strongly; males fan their tail feathers and gobble to attract mates."}, "northern-cardinal": {"name": "Northern cardinal", "cat": "bird", "group": "songbird (bird)", "hab": "forest edges and clearings", "habKey": "edge", "diet": "seeds and nuts", "art": "bird", "trait": "The bright red male sings year-round, and unlike most songbirds the female sings too."}, "american-robin": {"name": "American robin", "cat": "bird", "group": "songbird (bird)", "hab": "towns, parks and gardens", "habKey": "urban", "diet": "a wide range of plant and animal foods", "art": "bird", "trait": "A familiar lawn forager, it tilts its head not to listen but to look sideways for earthworms."}, "blue-jay": {"name": "Blue jay", "cat": "bird", "group": "songbird (bird)", "hab": "forests and woodlands", "habKey": "forest", "diet": "a wide range of plant and animal foods", "art": "bird", "trait": "A clever, noisy bird that buries acorns for winter and can mimic the scream of a hawk to scare other birds."}, "black-capped-chickadee": {"name": "Black-capped chickadee", "cat": "bird", "group": "songbird (bird)", "hab": "forests and woodlands", "habKey": "forest", "diet": "insects and other small invertebrates", "art": "bird", "trait": "It hides thousands of seeds and grows extra brain cells each fall to help it remember where."}, "american-crow": {"name": "American crow", "cat": "bird", "group": "songbird (bird)", "hab": "many habitats across North America", "habKey": "widespread", "diet": "a wide range of plant and animal foods", "art": "bird", "trait": "One of the smartest birds, it can use simple tools, recognize human faces, and remember them for years."}, "ruby-throated-hummingbird": {"name": "Ruby-throated hummingbird", "cat": "bird", "group": "hummingbird (bird)", "hab": "forest edges and clearings", "habKey": "edge", "diet": "flower nectar", "art": "bird", "trait": "It beats its wings about 50 times a second and can fly backwards, even crossing the Gulf of Mexico nonstop."}, "pileated-woodpecker": {"name": "Pileated woodpecker", "cat": "bird", "group": "woodpecker (bird)", "hab": "forests and woodlands", "habKey": "forest", "diet": "insects and other small invertebrates", "art": "bird", "trait": "A crow-sized woodpecker with a flaming red crest, it chisels large rectangular holes to hunt carpenter ants."}, "great-blue-heron": {"name": "Great blue heron", "cat": "bird", "group": "wading bird", "hab": "wetlands and marshes", "habKey": "wetland", "diet": "fish and other water animals", "art": "wetland", "trait": "It stalks the shallows on long stilt-like legs and spears fish with a lightning jab of its dagger-like bill."}, "sandhill-crane": {"name": "Sandhill crane", "cat": "bird", "group": "crane (bird)", "hab": "wetlands and marshes", "habKey": "wetland", "diet": "a wide range of plant and animal foods", "art": "wetland", "trait": "Famous for its leaping courtship dances, it gathers by the hundreds of thousands along rivers during migration."}, "mallard": {"name": "Mallard", "cat": "bird", "group": "duck (bird)", "hab": "wetlands and marshes", "habKey": "wetland", "diet": "a wide range of plant and animal foods", "art": "wetland", "trait": "The familiar green-headed duck and ancestor of most farm ducks, it 'dabbles' tail-up to feed just under the surface."}, "canada-goose": {"name": "Canada goose", "cat": "bird", "group": "goose (bird)", "hab": "lakes and ponds", "habKey": "lake", "diet": "plants, leaves and shoots", "art": "wetland", "trait": "It flies in a V formation to save energy and mates for life, fiercely defending its goslings."}, "american-goldfinch": {"name": "American goldfinch", "cat": "bird", "group": "songbird (bird)", "hab": "meadows and open fields", "habKey": "meadow", "diet": "seeds and nuts", "art": "bird", "trait": "A strict seed-eater, it nests late in summer so its chicks hatch when thistle and sunflower seeds are ripe."}, "eastern-bluebird": {"name": "Eastern bluebird", "cat": "bird", "group": "songbird (bird)", "hab": "meadows and open fields", "habKey": "meadow", "diet": "insects and other small invertebrates", "art": "bird", "trait": "It nests in tree holes and nest boxes and drops from a perch to snatch insects off the ground."}, "peregrine-falcon": {"name": "Peregrine falcon", "cat": "bird", "group": "raptor (bird)", "hab": "coastal dunes and shores", "habKey": "coastal", "diet": "animals it hunts", "art": "coast", "trait": "In a hunting dive it can exceed 320 km/h, making it the fastest animal on the planet."}, "american-kestrel": {"name": "American kestrel", "cat": "bird", "group": "raptor (bird)", "hab": "grasslands and prairies", "habKey": "grass", "diet": "insects and other small invertebrates", "art": "bird", "trait": "North America's smallest falcon, it can hover in place over a field while hunting insects and mice."}, "turkey-vulture": {"name": "Turkey vulture", "cat": "bird", "group": "raptor (bird)", "hab": "many habitats across North America", "habKey": "widespread", "diet": "carrion (already-dead animals)", "art": "bird", "trait": "It soars for hours rarely flapping, and unusually for a bird it finds its food, carrion, by smell."}, "common-loon": {"name": "Common loon", "cat": "bird", "group": "water bird", "hab": "lakes and ponds", "habKey": "lake", "diet": "fish and other water animals", "art": "wetland", "trait": "A powerful diver with unusually solid bones, it can plunge dozens of meters after fish and gives an eerie, wailing call."}, "eastern-box-turtle": {"name": "Eastern box turtle", "cat": "reptile", "group": "turtle (reptile)", "hab": "forests and woodlands", "habKey": "forest", "diet": "a wide range of plant and animal foods", "art": "reptile", "trait": "Its hinged shell can close fully like a box, and a single turtle may live more than 80 years in one small patch of woods."}, "snapping-turtle": {"name": "Common snapping turtle", "cat": "reptile", "group": "turtle (reptile)", "hab": "wetlands and marshes", "habKey": "wetland", "diet": "a wide range of plant and animal foods", "art": "pond", "trait": "A heavy freshwater turtle with powerful jaws, it lurks buried in mud and ambushes prey that passes overhead."}, "painted-turtle": {"name": "Painted turtle", "cat": "reptile", "group": "turtle (reptile)", "hab": "lakes and ponds", "habKey": "lake", "diet": "a wide range of plant and animal foods", "art": "pond", "trait": "The most widespread turtle in North America, it basks in rows on logs, and its hatchlings can survive winter frozen in the nest."}, "american-alligator": {"name": "American alligator", "cat": "reptile", "group": "reptile (crocodilian)", "hab": "wetlands and marshes", "habKey": "wetland", "diet": "animals it hunts", "art": "pond", "trait": "A conservation success story, it digs 'gator holes' that hold water and shelter other wetland life during droughts."}, "western-diamondback": {"name": "Western diamondback rattlesnake", "cat": "reptile", "group": "snake (reptile)", "hab": "deserts and dry scrub", "habKey": "desert", "diet": "animals it hunts", "art": "desert", "trait": "It warns intruders by buzzing the rattle on its tail and senses warm prey with heat-detecting pits on its face."}, "garter-snake": {"name": "Common garter snake", "cat": "reptile", "group": "snake (reptile)", "hab": "many habitats across North America", "habKey": "widespread", "diet": "frogs, insects and other small prey", "art": "reptile", "trait": "One of the most common snakes, it is harmless to people and tolerates cold so well that it is often the first snake out in spring."}, "gopher-snake": {"name": "Gopher snake", "cat": "reptile", "group": "snake (reptile)", "hab": "grasslands and prairies", "habKey": "grass", "diet": "small mammals like mice and rabbits", "art": "reptile", "trait": "A large, nonvenomous snake, it hisses and vibrates its tail to bluff like a rattlesnake when it is cornered."}, "eastern-fence-lizard": {"name": "Eastern fence lizard", "cat": "reptile", "group": "lizard (reptile)", "hab": "forests and woodlands", "habKey": "forest", "diet": "insects and other small invertebrates", "art": "reptile", "trait": "It scurries up the far side of a tree to escape, and in some areas has evolved longer legs to flee invasive fire ants."}, "green-anole": {"name": "Green anole", "cat": "reptile", "group": "lizard (reptile)", "hab": "forest edges and clearings", "habKey": "edge", "diet": "insects and other small invertebrates", "art": "reptile", "trait": "It can shift from green to brown with its mood and temperature, and males flash a pink throat-fan at rivals."}, "desert-tortoise": {"name": "Desert tortoise", "cat": "reptile", "group": "tortoise (reptile)", "hab": "deserts and dry scrub", "habKey": "desert", "diet": "plants, leaves and shoots", "art": "desert", "trait": "It survives blistering deserts by digging deep burrows and storing water in its bladder for the dry months."}, "american-bullfrog": {"name": "American bullfrog", "cat": "amphibian", "group": "frog (amphibian)", "hab": "wetlands and marshes", "habKey": "wetland", "diet": "animals it hunts", "art": "frog", "trait": "The largest frog in North America, its deep 'jug-o-rum' call carries far, and it will eat almost anything it can swallow."}, "spring-peeper": {"name": "Spring peeper", "cat": "amphibian", "group": "frog (amphibian)", "hab": "wetlands and marshes", "habKey": "wetland", "diet": "insects and other small invertebrates", "art": "frog", "trait": "A tiny tree frog, its loud peeping chorus on cool evenings is one of the first sounds of spring."}, "american-toad": {"name": "American toad", "cat": "amphibian", "group": "toad (amphibian)", "hab": "forest edges and clearings", "habKey": "edge", "diet": "insects and other small invertebrates", "art": "frog", "trait": "Its warty skin oozes a mild poison that deters predators, and it can eat thousands of insects in a single season."}, "wood-frog": {"name": "Wood frog", "cat": "amphibian", "group": "frog (amphibian)", "hab": "moist shady forests", "habKey": "wetforest", "diet": "insects and other small invertebrates", "art": "frog", "trait": "It can survive being frozen nearly solid each winter, its heart stopping, then thaw out and hop away in spring."}, "eastern-newt": {"name": "Eastern newt", "cat": "amphibian", "group": "salamander (amphibian)", "hab": "lakes and ponds", "habKey": "lake", "diet": "insects and other small invertebrates", "art": "pond", "trait": "Its bright orange land-living 'eft' stage warns predators that it is toxic before it returns to the water as an adult."}, "spotted-salamander": {"name": "Spotted salamander", "cat": "amphibian", "group": "salamander (amphibian)", "hab": "moist shady forests", "habKey": "wetforest", "diet": "insects and other small invertebrates", "art": "frog", "trait": "It spends most of its life hidden underground, emerging on rainy spring nights to breed in temporary woodland pools."}, "hellbender": {"name": "Hellbender", "cat": "amphibian", "group": "salamander (amphibian)", "hab": "rivers and streams", "habKey": "river", "diet": "insects and other small invertebrates", "art": "pond", "trait": "North America's largest salamander, it breathes through wrinkly folds of skin and needs cold, clean, fast-flowing streams."}, "brook-trout": {"name": "Brook trout", "cat": "freshwater fish", "group": "freshwater fish", "hab": "rivers and streams", "habKey": "river", "diet": "insects and other small invertebrates", "art": "fish", "trait": "A jewel-toned native of cold mountain streams, it is so sensitive to warmth and pollution that its presence signals clean water."}, "rainbow-trout": {"name": "Rainbow trout", "cat": "freshwater fish", "group": "freshwater fish", "hab": "rivers and streams", "habKey": "river", "diet": "insects and other small invertebrates", "art": "fish", "trait": "Named for the pink stripe along its side, it is prized by anglers and can leap waterfalls to reach its spawning grounds."}, "largemouth-bass": {"name": "Largemouth bass", "cat": "freshwater fish", "group": "freshwater fish", "hab": "lakes and ponds", "habKey": "lake", "diet": "fish and other water animals", "art": "fish", "trait": "A favorite sport fish, the male sweeps out a nest, fans the eggs to keep them clean, and then guards the young fry."}, "bluegill": {"name": "Bluegill", "cat": "freshwater fish", "group": "sunfish (freshwater fish)", "hab": "lakes and ponds", "habKey": "lake", "diet": "insects and other small invertebrates", "art": "fish", "trait": "A common panfish, the male sweeps out saucer-shaped nests in the shallows and defends them fiercely."}, "channel-catfish": {"name": "Channel catfish", "cat": "freshwater fish", "group": "freshwater fish", "hab": "rivers and streams", "habKey": "river", "diet": "a wide range of plant and animal foods", "art": "fish", "trait": "It 'tastes' the water with whisker-like barbels and has taste buds scattered all over its body to find food in the dark."}, "monarch-butterfly": {"name": "Monarch butterfly", "cat": "insect", "group": "butterfly (insect)", "hab": "meadows and open fields", "habKey": "meadow", "diet": "flower nectar", "art": "butterfly", "trait": "Its orange wings warn that it is toxic, and it migrates thousands of kilometers to the same Mexican forests each year."}, "tiger-swallowtail": {"name": "Eastern tiger swallowtail", "cat": "insect", "group": "butterfly (insect)", "hab": "forests and woodlands", "habKey": "forest", "diet": "flower nectar", "art": "butterfly", "trait": "A large yellow-and-black butterfly whose caterpillar has fake eyespots that make it look like a small snake."}, "honey-bee": {"name": "Western honey bee", "cat": "insect", "group": "bee (insect)", "hab": "meadows and open fields", "habKey": "meadow", "diet": "pollen and nectar", "art": "butterfly", "trait": "It tells hive-mates where flowers are by dancing, and a strong colony can visit millions of blossoms a day."}, "bumble-bee": {"name": "Common eastern bumble bee", "cat": "insect", "group": "bee (insect)", "hab": "meadows and open fields", "habKey": "meadow", "diet": "pollen and nectar", "art": "butterfly", "trait": "It can fly in cool weather by shivering to warm up, and 'buzz-pollinates' flowers that honey bees cannot."}, "firefly": {"name": "Common eastern firefly", "cat": "insect", "group": "beetle (insect)", "hab": "meadows and open fields", "habKey": "meadow", "diet": "insects and other small invertebrates", "art": "butterfly", "trait": "It is not a fly but a beetle, flashing a coded light from its belly to find a mate on summer nights."}, "lady-beetle": {"name": "Convergent lady beetle", "cat": "insect", "group": "beetle (insect)", "hab": "meadows and open fields", "habKey": "meadow", "diet": "insects and other small invertebrates", "art": "butterfly", "trait": "A gardener's friend, a single ladybug can eat thousands of plant-sucking aphids over its life."}, "green-darner": {"name": "Common green darner", "cat": "insect", "group": "dragonfly (insect)", "hab": "wetlands and marshes", "habKey": "wetland", "diet": "insects and other small invertebrates", "art": "butterfly", "trait": "One of the fastest insects, it catches prey in mid-air with a basket of legs, and some even migrate like birds."}, "carolina-mantis": {"name": "Carolina mantis", "cat": "insect", "group": "mantis (insect)", "hab": "meadows and open fields", "habKey": "meadow", "diet": "insects and other small invertebrates", "art": "butterfly", "trait": "It can swivel its head almost all the way around and seizes prey with lightning-fast, spined front legs."}, "luna-moth": {"name": "Luna moth", "cat": "insect", "group": "moth (insect)", "hab": "forests and woodlands", "habKey": "forest", "diet": "", "art": "butterfly", "trait": "A large, pale-green moth with long tails, the adult has no mouth and lives only about a week, just long enough to mate."}, "periodical-cicada": {"name": "Periodical cicada", "cat": "insect", "group": "cicada (insect)", "hab": "forests and woodlands", "habKey": "forest", "diet": "", "art": "butterfly", "trait": "It spends 13 or 17 years underground as a nymph, then emerges in vast synchronized swarms to sing and mate."}, "carpenter-ant": {"name": "Black carpenter ant", "cat": "insect", "group": "ant (insect)", "hab": "forests and woodlands", "habKey": "forest", "diet": "a wide range of plant and animal foods", "art": "butterfly", "trait": "It does not eat wood but tunnels through damp, rotting wood to nest, helping to break down dead trees."}, "garden-spider": {"name": "Yellow garden spider", "cat": "arachnid", "group": "spider (arachnid)", "hab": "meadows and open fields", "habKey": "meadow", "diet": "insects and other small invertebrates", "art": "fern", "trait": "It weaves a zigzag band of silk down the center of its wheel-shaped web, then waits head-down for prey."}, "wolf-spider": {"name": "Wolf spider", "cat": "arachnid", "group": "spider (arachnid)", "hab": "grasslands and prairies", "habKey": "grass", "diet": "insects and other small invertebrates", "art": "fern", "trait": "Rather than build a web, it chases down prey on foot and carries its egg sac, and later its babies, on its back."}, "granite": {"name": "Granite", "cat": "rock", "group": "igneous rock", "hab": "", "habKey": null, "diet": "", "art": "mineral", "trait": "Formed deep underground from slowly cooled magma, its coarse crystals of quartz and feldspar make it hard and long-lasting."}, "basalt": {"name": "Basalt", "cat": "rock", "group": "igneous rock", "hab": "", "habKey": null, "diet": "", "art": "mineral", "trait": "It forms when lava cools quickly at the surface, building vast lava plains and most of the ocean floor."}, "obsidian": {"name": "Obsidian", "cat": "rock", "group": "igneous rock", "hab": "", "habKey": null, "diet": "", "art": "mineral", "trait": "It is volcanic glass, formed when lava cools so fast that no crystals can grow, and it can be flaked razor-sharp."}, "pumice": {"name": "Pumice", "cat": "rock", "group": "igneous rock", "hab": "", "habKey": null, "diet": "", "art": "mineral", "trait": "So full of frozen gas bubbles that it can float on water, it forms from frothy lava blasted out of a volcano."}, "sandstone": {"name": "Sandstone", "cat": "rock", "group": "sedimentary rock", "hab": "", "habKey": null, "diet": "", "art": "mineral", "trait": "Made of sand grains cemented together, it often preserves ripple marks and forms colorful canyon walls and arches."}, "limestone": {"name": "Limestone", "cat": "rock", "group": "sedimentary rock", "hab": "", "habKey": null, "diet": "", "art": "mineral", "trait": "Built largely from the shells and skeletons of sea creatures, it slowly dissolves in mild acid to form caves."}, "shale": {"name": "Shale", "cat": "rock", "group": "sedimentary rock", "hab": "", "habKey": null, "diet": "", "art": "mineral", "trait": "Formed from compacted mud and clay, it splits into thin flat layers and often holds the best-preserved fossils."}, "conglomerate": {"name": "Conglomerate", "cat": "rock", "group": "sedimentary rock", "hab": "", "habKey": null, "diet": "", "art": "mineral", "trait": "A natural concrete of rounded pebbles cemented together, it forms in fast water like riverbeds and beaches."}, "coal": {"name": "Coal", "cat": "rock", "group": "sedimentary rock", "hab": "", "habKey": null, "diet": "", "art": "mineral", "trait": "It forms over millions of years from buried plant matter squeezed under heat and pressure, storing ancient sunlight as fuel."}, "marble": {"name": "Marble", "cat": "rock", "group": "metamorphic rock", "hab": "", "habKey": null, "diet": "", "art": "mineral", "trait": "It begins as limestone, then heat and pressure recrystallize it into the smooth stone that sculptors love to carve."}, "slate": {"name": "Slate", "cat": "rock", "group": "metamorphic rock", "hab": "", "habKey": null, "diet": "", "art": "mineral", "trait": "Heat and pressure turn shale into slate, which splits into flat sheets once widely used for roofs and chalkboards."}, "gneiss": {"name": "Gneiss", "cat": "rock", "group": "metamorphic rock", "hab": "", "habKey": null, "diet": "", "art": "mineral", "trait": "Intense heat and pressure squeeze its minerals into striking light-and-dark bands, and it is among the oldest rock on Earth."}, "quartzite": {"name": "Quartzite", "cat": "rock", "group": "metamorphic rock", "hab": "", "habKey": null, "diet": "", "art": "mineral", "trait": "Sandstone baked and pressed until its grains fuse together, it becomes so hard it resists almost all weathering."}, "quartz": {"name": "Quartz", "cat": "mineral", "group": "mineral", "hab": "", "habKey": null, "diet": "", "art": "mineral", "trait": "One of the most common minerals, it grows six-sided crystals and comes in colorful forms like purple amethyst and yellow citrine."}, "feldspar": {"name": "Feldspar", "cat": "mineral", "group": "mineral", "hab": "", "habKey": null, "diet": "", "art": "mineral", "trait": "The most abundant mineral group in Earth's crust, it slowly weathers into the clay that helps build soil."}, "calcite": {"name": "Calcite", "cat": "mineral", "group": "mineral", "hab": "", "habKey": null, "diet": "", "art": "mineral", "trait": "It fizzes in weak acid and can split light into a double image, and it is the mineral that builds limestone and marble."}, "pyrite": {"name": "Pyrite", "cat": "mineral", "group": "mineral", "hab": "", "habKey": null, "diet": "", "art": "mineral", "trait": "Its shiny brassy cubes earned the nickname 'fool's gold,' though it is far harder and lighter than real gold."}, "mica": {"name": "Mica", "cat": "mineral", "group": "mineral", "hab": "", "habKey": null, "diet": "", "art": "mineral", "trait": "It peels apart into thin, flexible, see-through sheets and adds the glitter you can see in many rocks."}, "gypsum": {"name": "Gypsum", "cat": "mineral", "group": "mineral", "hab": "", "habKey": null, "diet": "", "art": "mineral", "trait": "So soft you can scratch it with a fingernail, it is ground up to make the plaster inside drywall."}, "hematite": {"name": "Hematite", "cat": "mineral", "group": "mineral", "hab": "", "habKey": null, "diet": "", "art": "mineral", "trait": "A major ore of iron, it leaves a rust-red streak and tints many rocks and soils a reddish color."}, "fluorite": {"name": "Fluorite", "cat": "mineral", "group": "mineral", "hab": "", "habKey": null, "diet": "", "art": "mineral", "trait": "It forms colorful cube-shaped crystals and glows under ultraviolet light, the very origin of the word 'fluorescent.'"}, "halite": {"name": "Halite", "cat": "mineral", "group": "mineral", "hab": "", "habKey": null, "diet": "", "art": "mineral", "trait": "This is rock salt, the same salt you eat, left behind when ancient seas and salty lakes dried up."}, "trilobite": {"name": "Trilobite", "cat": "fossil", "group": "fossil", "hab": "", "habKey": null, "diet": "", "art": "fossil", "trait": "These hard-shelled sea animals ruled the oceans for nearly 300 million years before vanishing, and are common fossils today."}, "ammonite": {"name": "Ammonite", "cat": "fossil", "group": "fossil", "hab": "", "habKey": null, "diet": "", "art": "fossil", "trait": "The coiled, chambered shells of these ancient relatives of squid are prized fossils, often shimmering with color."}, "petrified-wood": {"name": "Petrified wood", "cat": "fossil", "group": "fossil", "hab": "", "habKey": null, "diet": "", "art": "fossil", "trait": "Ancient buried wood whose every cell was slowly replaced by minerals, turning a log to colorful stone that still shows its rings."}, "dinosaur-bone": {"name": "Dinosaur bone", "cat": "fossil", "group": "fossil", "hab": "", "habKey": null, "diet": "", "art": "fossil", "trait": "Buried bone in which minerals filled and replaced the original tissue tells us about animals that lived millions of years ago."}, "amber": {"name": "Amber", "cat": "fossil", "group": "fossil", "hab": "", "habKey": null, "diet": "", "art": "fossil", "trait": "Hardened tree resin from long-dead forests, it sometimes traps and perfectly preserves ancient insects inside."}, "wood-duck": {"name": "Wood duck", "cat": "bird", "group": "duck (bird)", "hab": "wetlands and marshes", "habKey": "wetland", "diet": "a wide range of plant and animal foods", "art": "wetland", "trait": "The male is among the most colorful of all waterfowl, and ducklings leap from the high tree-hole nest the day after they hatch."}, "northern-pintail": {"name": "Northern pintail", "cat": "bird", "group": "duck (bird)", "hab": "wetlands and marshes", "habKey": "wetland", "diet": "a wide range of plant and animal foods", "art": "wetland", "trait": "A slender, elegant duck named for the male's long, pointed tail; it is a strong long-distance migrant."}, "american-wigeon": {"name": "American wigeon", "cat": "bird", "group": "duck (bird)", "hab": "wetlands and marshes", "habKey": "wetland", "diet": "plants, leaves and shoots", "art": "wetland", "trait": "The male's white crown earns it the nickname 'baldpate,' and it often snatches plants that diving birds bring up."}, "green-winged-teal": {"name": "Green-winged teal", "cat": "bird", "group": "duck (bird)", "hab": "wetlands and marshes", "habKey": "wetland", "diet": "a wide range of plant and animal foods", "art": "wetland", "trait": "The smallest North American dabbling duck, it twists and turns in fast, tight flocks."}, "northern-shoveler": {"name": "Northern shoveler", "cat": "bird", "group": "duck (bird)", "hab": "wetlands and marshes", "habKey": "wetland", "diet": "a wide range of plant and animal foods", "art": "wetland", "trait": "Its huge spoon-shaped bill is lined with comb-like teeth that strain tiny food from the water."}, "canvasback": {"name": "Canvasback", "cat": "bird", "group": "duck (bird)", "hab": "lakes and ponds", "habKey": "lake", "diet": "water plants", "art": "wetland", "trait": "A fast-flying diving duck with a sloping forehead, it dives to feed on roots and plants on the bottom."}, "ruddy-duck": {"name": "Ruddy duck", "cat": "bird", "group": "duck (bird)", "hab": "lakes and ponds", "habKey": "lake", "diet": "water plants", "art": "wetland", "trait": "A small, stiff-tailed diving duck whose breeding male sports a bright sky-blue bill."}, "hooded-merganser": {"name": "Hooded merganser", "cat": "bird", "group": "duck (bird)", "hab": "lakes and ponds", "habKey": "lake", "diet": "fish and other water animals", "art": "wetland", "trait": "It can raise a striking fan-shaped crest, and it dives for fish gripping them with a thin, saw-edged bill."}, "common-merganser": {"name": "Common merganser", "cat": "bird", "group": "duck (bird)", "hab": "rivers and streams", "habKey": "river", "diet": "fish and other water animals", "art": "wetland", "trait": "A sleek fish-eating diving duck whose serrated 'sawbill' helps it hold slippery prey."}, "trumpeter-swan": {"name": "Trumpeter swan", "cat": "bird", "group": "swan (bird)", "hab": "lakes and ponds", "habKey": "lake", "diet": "water plants", "art": "wetland", "trait": "The heaviest native waterfowl in North America, it was nearly hunted to extinction before a remarkable recovery."}, "tundra-swan": {"name": "Tundra swan", "cat": "bird", "group": "swan (bird)", "hab": "wetlands and marshes", "habKey": "wetland", "diet": "water plants", "art": "wetland", "trait": "It nests on the Arctic tundra and migrates south in long, calling V-formations each winter."}, "snow-goose": {"name": "Snow goose", "cat": "bird", "group": "goose (bird)", "hab": "wetlands and marshes", "habKey": "wetland", "diet": "plants, leaves and shoots", "art": "wetland", "trait": "It migrates in enormous, noisy flocks and comes in a white form and a dark 'blue' form."}, "american-coot": {"name": "American coot", "cat": "bird", "group": "water bird", "hab": "lakes and ponds", "habKey": "lake", "diet": "water plants", "art": "wetland", "trait": "Though it swims like a duck, it is actually a rail, and it has lobed rather than webbed toes."}, "pied-billed-grebe": {"name": "Pied-billed grebe", "cat": "bird", "group": "water bird", "hab": "lakes and ponds", "habKey": "lake", "diet": "fish and other water animals", "art": "wetland", "trait": "It can sink slowly out of sight like a submarine by squeezing the air out of its feathers."}, "double-crested-cormorant": {"name": "Double-crested cormorant", "cat": "bird", "group": "water bird", "hab": "lakes and ponds", "habKey": "lake", "diet": "fish and other water animals", "art": "wetland", "trait": "After diving for fish it perches with wings spread to dry, because its feathers are not fully waterproof."}, "american-white-pelican": {"name": "American white pelican", "cat": "bird", "group": "water bird", "hab": "lakes and ponds", "habKey": "lake", "diet": "fish and other water animals", "art": "wetland", "trait": "One of the largest North American birds, groups of them herd fish into the shallows and scoop them up together."}, "belted-kingfisher": {"name": "Belted kingfisher", "cat": "bird", "group": "water bird", "hab": "rivers and streams", "habKey": "river", "diet": "fish and other water animals", "art": "wetland", "trait": "It plunges headfirst from a perch to catch fish, and unusually the female is more colorful than the male."}, "great-egret": {"name": "Great egret", "cat": "bird", "group": "wading bird", "hab": "wetlands and marshes", "habKey": "wetland", "diet": "fish and other water animals", "art": "wetland", "trait": "This tall white heron was hunted nearly to extinction for the long plumes it grows in the breeding season."}, "snowy-egret": {"name": "Snowy egret", "cat": "bird", "group": "wading bird", "hab": "wetlands and marshes", "habKey": "wetland", "diet": "fish and other water animals", "art": "wetland", "trait": "It has black legs and bright yellow feet, which it shuffles in the water to stir up hidden prey."}, "green-heron": {"name": "Green heron", "cat": "bird", "group": "wading bird", "hab": "wetlands and marshes", "habKey": "wetland", "diet": "fish and other water animals", "art": "wetland", "trait": "One of the few tool-using birds, it drops insects or feathers onto the water as bait to lure fish."}, "black-crowned-night-heron": {"name": "Black-crowned night-heron", "cat": "bird", "group": "wading bird", "hab": "wetlands and marshes", "habKey": "wetland", "diet": "fish and other water animals", "art": "wetland", "trait": "It hunts mostly at dusk and through the night, when taller daytime herons are roosting."}, "american-bittern": {"name": "American bittern", "cat": "bird", "group": "wading bird", "hab": "wetlands and marshes", "habKey": "wetland", "diet": "fish and other water animals", "art": "wetland", "trait": "When alarmed it freezes with its striped neck and bill pointed straight up, vanishing among the reeds."}, "killdeer": {"name": "Killdeer", "cat": "bird", "group": "shorebird (bird)", "hab": "meadows and open fields", "habKey": "meadow", "diet": "insects and other small invertebrates", "art": "bird", "trait": "To protect its ground nest it fakes a broken wing, luring predators away before flying off unharmed."}, "american-woodcock": {"name": "American woodcock", "cat": "bird", "group": "shorebird (bird)", "hab": "moist shady forests", "habKey": "wetforest", "diet": "insects and other small invertebrates", "art": "bird", "trait": "A plump shorebird of damp woods, the male performs a spiraling 'sky dance' high overhead at dusk."}, "spotted-sandpiper": {"name": "Spotted sandpiper", "cat": "bird", "group": "shorebird (bird)", "hab": "rivers and streams", "habKey": "river", "diet": "insects and other small invertebrates", "art": "wetland", "trait": "It teeters and bobs its tail constantly, and the female often mates with several males who raise the chicks."}, "greater-yellowlegs": {"name": "Greater yellowlegs", "cat": "bird", "group": "shorebird (bird)", "hab": "wetlands and marshes", "habKey": "wetland", "diet": "insects and other small invertebrates", "art": "wetland", "trait": "A tall, watchful wader on bright yellow legs, it gives loud ringing alarm calls across the marsh."}, "ring-billed-gull": {"name": "Ring-billed gull", "cat": "bird", "group": "gull (bird)", "hab": "lakes and ponds", "habKey": "lake", "diet": "a wide range of plant and animal foods", "art": "wetland", "trait": "The familiar 'parking-lot gull,' it is named for the neat black ring around its yellow bill."}, "red-bellied-woodpecker": {"name": "Red-bellied woodpecker", "cat": "bird", "group": "woodpecker (bird)", "hab": "forests and woodlands", "habKey": "forest", "diet": "a wide range of plant and animal foods", "art": "bird", "trait": "Despite the name, the boldest mark is the red cap on its head; the pale belly blush is hard to see."}, "downy-woodpecker": {"name": "Downy woodpecker", "cat": "bird", "group": "woodpecker (bird)", "hab": "forests and woodlands", "habKey": "forest", "diet": "insects and other small invertebrates", "art": "bird", "trait": "The smallest woodpecker in North America, it is a frequent and acrobatic visitor to backyard feeders."}, "hairy-woodpecker": {"name": "Hairy woodpecker", "cat": "bird", "group": "woodpecker (bird)", "hab": "forests and woodlands", "habKey": "forest", "diet": "insects and other small invertebrates", "art": "bird", "trait": "It looks like a larger twin of the downy woodpecker but has a noticeably longer, chisel-like bill."}, "northern-flicker": {"name": "Northern flicker", "cat": "bird", "group": "woodpecker (bird)", "hab": "forest edges and clearings", "habKey": "edge", "diet": "insects and other small invertebrates", "art": "bird", "trait": "Unusual among woodpeckers, it often feeds on the ground, using its long tongue to lap up ants."}, "red-headed-woodpecker": {"name": "Red-headed woodpecker", "cat": "bird", "group": "woodpecker (bird)", "hab": "forest edges and clearings", "habKey": "edge", "diet": "a wide range of plant and animal foods", "art": "bird", "trait": "Its entire head is bright crimson, and it is skilled enough to catch insects on the wing and store food."}, "yellow-bellied-sapsucker": {"name": "Yellow-bellied sapsucker", "cat": "bird", "group": "woodpecker (bird)", "hab": "forests and woodlands", "habKey": "forest", "diet": "insects and other small invertebrates", "art": "bird", "trait": "It drills neat rows of small holes, called sap wells, in tree bark and feeds on the oozing sap."}, "acorn-woodpecker": {"name": "Acorn woodpecker", "cat": "bird", "group": "woodpecker (bird)", "hab": "forests and woodlands", "habKey": "forest", "diet": "insects and other small invertebrates", "art": "bird", "trait": "It drills holes in 'granary' trees and wedges thousands of acorns into them, one per hole, to store for winter."}, "northern-bobwhite": {"name": "Northern bobwhite", "cat": "bird", "group": "game bird", "hab": "grasslands and prairies", "habKey": "grass", "diet": "seeds and nuts", "art": "bird", "trait": "A small quail named for the male's clear, whistled 'bob-WHITE' call ringing across grassy fields."}, "mourning-dove": {"name": "Mourning dove", "cat": "bird", "group": "dove (bird)", "hab": "towns, parks and gardens", "habKey": "urban", "diet": "seeds and nuts", "art": "bird", "trait": "Its soft, mournful cooing is often mistaken for an owl, and it is one of the most abundant birds in North America."}, "rock-pigeon": {"name": "Rock pigeon", "cat": "bird", "group": "dove (bird)", "hab": "towns, parks and gardens", "habKey": "urban", "diet": "seeds and nuts", "art": "bird", "trait": "The familiar city pigeon, it descends from wild doves that nested on sea cliffs and rocky ledges."}, "white-breasted-nuthatch": {"name": "White-breasted nuthatch", "cat": "bird", "group": "songbird (bird)", "hab": "forests and woodlands", "habKey": "forest", "diet": "insects and other small invertebrates", "art": "bird", "trait": "It walks headfirst down tree trunks, an upside-down view that helps it spot food other birds miss."}, "red-breasted-nuthatch": {"name": "Red-breasted nuthatch", "cat": "bird", "group": "songbird (bird)", "hab": "coniferous forests", "habKey": "conifer", "diet": "insects and other small invertebrates", "art": "bird", "trait": "It smears sticky tree sap around the entrance of its nest hole, apparently to keep intruders out."}, "brown-creeper": {"name": "Brown creeper", "cat": "bird", "group": "songbird (bird)", "hab": "forests and woodlands", "habKey": "forest", "diet": "insects and other small invertebrates", "art": "bird", "trait": "It spirals up a tree trunk probing the bark for insects, then flutters down to start up the next tree."}, "tufted-titmouse": {"name": "Tufted titmouse", "cat": "bird", "group": "songbird (bird)", "hab": "forests and woodlands", "habKey": "forest", "diet": "seeds and nuts", "art": "bird", "trait": "A perky crested songbird, it will sometimes pluck hair from a living animal to line its nest."}, "carolina-wren": {"name": "Carolina wren", "cat": "bird", "group": "songbird (bird)", "hab": "forest edges and clearings", "habKey": "edge", "diet": "insects and other small invertebrates", "art": "bird", "trait": "Tiny but startlingly loud, the male belts out a ringing 'tea-kettle, tea-kettle, tea-kettle' song."}, "house-wren": {"name": "House wren", "cat": "bird", "group": "songbird (bird)", "hab": "towns, parks and gardens", "habKey": "urban", "diet": "insects and other small invertebrates", "art": "bird", "trait": "A plain but feisty little bird, it crams nest boxes full of twigs and fiercely defends its territory."}, "american-dipper": {"name": "American dipper", "cat": "bird", "group": "songbird (bird)", "hab": "rivers and streams", "habKey": "river", "diet": "insects and other small invertebrates", "art": "wetland", "trait": "North America's only truly aquatic songbird, it walks along the bottom of cold mountain streams to feed."}, "cedar-waxwing": {"name": "Cedar waxwing", "cat": "bird", "group": "songbird (bird)", "hab": "forest edges and clearings", "habKey": "edge", "diet": "fruit and berries", "art": "bird", "trait": "Sleek and social, it feeds in flocks on berries and has bright waxy-red tips on its wing feathers."}, "gray-catbird": {"name": "Gray catbird", "cat": "bird", "group": "songbird (bird)", "hab": "forest edges and clearings", "habKey": "edge", "diet": "a wide range of plant and animal foods", "art": "bird", "trait": "It mews like a cat and stitches snippets of other birds' songs into its own rambling tune."}, "northern-mockingbird": {"name": "Northern mockingbird", "cat": "bird", "group": "songbird (bird)", "hab": "towns, parks and gardens", "habKey": "urban", "diet": "a wide range of plant and animal foods", "art": "bird", "trait": "It can learn and imitate hundreds of sounds, copying other birds and even car alarms and machines."}, "brown-thrasher": {"name": "Brown thrasher", "cat": "bird", "group": "songbird (bird)", "hab": "forest edges and clearings", "habKey": "edge", "diet": "a wide range of plant and animal foods", "art": "bird", "trait": "It has one of the largest song repertoires of any North American bird, with over a thousand song types."}, "eastern-towhee": {"name": "Eastern towhee", "cat": "bird", "group": "songbird (bird)", "hab": "forest edges and clearings", "habKey": "edge", "diet": "seeds and nuts", "art": "bird", "trait": "It scratches noisily in dead leaves, kicking backward with both feet at once to uncover seeds and bugs."}, "dark-eyed-junco": {"name": "Dark-eyed junco", "cat": "bird", "group": "songbird (bird)", "hab": "forests and woodlands", "habKey": "forest", "diet": "seeds and nuts", "art": "bird", "trait": "Often called the 'snowbird,' it flashes white outer tail feathers as it flits up from the ground."}, "song-sparrow": {"name": "Song sparrow", "cat": "bird", "group": "songbird (bird)", "hab": "forest edges and clearings", "habKey": "edge", "diet": "seeds and nuts", "art": "bird", "trait": "One of the most widespread sparrows, each male sings his own personal variation of the species' tune."}, "white-throated-sparrow": {"name": "White-throated sparrow", "cat": "bird", "group": "songbird (bird)", "hab": "forests and woodlands", "habKey": "forest", "diet": "seeds and nuts", "art": "bird", "trait": "It whistles a clear, wavering song that people often write as 'Oh sweet Canada, Canada, Canada.'"}, "white-crowned-sparrow": {"name": "White-crowned sparrow", "cat": "bird", "group": "songbird (bird)", "hab": "forest edges and clearings", "habKey": "edge", "diet": "seeds and nuts", "art": "bird", "trait": "Marked by a crisp black-and-white striped crown, it is a champion long-distance migrant."}, "chipping-sparrow": {"name": "Chipping sparrow", "cat": "bird", "group": "songbird (bird)", "hab": "towns, parks and gardens", "habKey": "urban", "diet": "seeds and nuts", "art": "bird", "trait": "A small, tidy sparrow with a rusty cap, it sings a long, dry, mechanical-sounding trill."}, "house-sparrow": {"name": "House sparrow", "cat": "bird", "group": "songbird (bird)", "hab": "towns, parks and gardens", "habKey": "urban", "diet": "seeds and nuts", "art": "bird", "trait": "Introduced from Europe, this non-native bird now lives around buildings and farms across the continent."}, "house-finch": {"name": "House finch", "cat": "bird", "group": "songbird (bird)", "hab": "towns, parks and gardens", "habKey": "urban", "diet": "seeds and nuts", "art": "bird", "trait": "The red color on the male comes from pigments in the food he eats, so diet can change how bright he is."}, "purple-finch": {"name": "Purple finch", "cat": "bird", "group": "songbird (bird)", "hab": "coniferous forests", "habKey": "conifer", "diet": "seeds and nuts", "art": "bird", "trait": "A famous guide described the rosy male as a sparrow 'dipped in raspberry juice.'"}, "pine-siskin": {"name": "Pine siskin", "cat": "bird", "group": "songbird (bird)", "hab": "coniferous forests", "habKey": "conifer", "diet": "seeds and nuts", "art": "bird", "trait": "A streaky little finch with yellow wing flashes, it wanders far and wide chasing good seed crops."}, "evening-grosbeak": {"name": "Evening grosbeak", "cat": "bird", "group": "songbird (bird)", "hab": "coniferous forests", "habKey": "conifer", "diet": "seeds and nuts", "art": "bird", "trait": "A chunky finch with a massive pale bill powerful enough to crack open hard cherry and other seeds."}, "indigo-bunting": {"name": "Indigo bunting", "cat": "bird", "group": "songbird (bird)", "hab": "forest edges and clearings", "habKey": "edge", "diet": "seeds and nuts", "art": "bird", "trait": "The male glows brilliant blue, though the color is really a trick of light, as the feathers are brown."}, "rose-breasted-grosbeak": {"name": "Rose-breasted grosbeak", "cat": "bird", "group": "songbird (bird)", "hab": "forests and woodlands", "habKey": "forest", "diet": "seeds and nuts", "art": "bird", "trait": "The male is black and white with a bright red splash on the chest, like a spilled drop of paint."}, "scarlet-tanager": {"name": "Scarlet tanager", "cat": "bird", "group": "songbird (bird)", "hab": "forests and woodlands", "habKey": "forest", "diet": "insects and other small invertebrates", "art": "bird", "trait": "In summer the male is brilliant scarlet with black wings, then molts to a dull yellow-green for winter."}, "baltimore-oriole": {"name": "Baltimore oriole", "cat": "bird", "group": "songbird (bird)", "hab": "forest edges and clearings", "habKey": "edge", "diet": "fruit and berries", "art": "bird", "trait": "It weaves a remarkable hanging, sock-shaped nest and is strongly drawn to oranges and ripe fruit."}, "red-winged-blackbird": {"name": "Red-winged blackbird", "cat": "bird", "group": "songbird (bird)", "hab": "wetlands and marshes", "habKey": "wetland", "diet": "seeds and nuts", "art": "wetland", "trait": "The male flashes scarlet shoulder patches and sings loudly to defend his patch of marsh."}, "common-grackle": {"name": "Common grackle", "cat": "bird", "group": "songbird (bird)", "hab": "towns, parks and gardens", "habKey": "urban", "diet": "a wide range of plant and animal foods", "art": "bird", "trait": "A long-tailed blackbird that gleams with iridescent purple and bronze and has a piercing pale eye."}, "brown-headed-cowbird": {"name": "Brown-headed cowbird", "cat": "bird", "group": "songbird (bird)", "hab": "forest edges and clearings", "habKey": "edge", "diet": "seeds and nuts", "art": "bird", "trait": "It lays its eggs in other birds' nests, leaving those parents to raise its chicks instead of their own."}, "eastern-meadowlark": {"name": "Eastern meadowlark", "cat": "bird", "group": "songbird (bird)", "hab": "grasslands and prairies", "habKey": "grass", "diet": "insects and other small invertebrates", "art": "bird", "trait": "A bird of open grasslands, it has a bright yellow chest crossed by a black V and a clear, flute-like song."}, "bobolink": {"name": "Bobolink", "cat": "bird", "group": "songbird (bird)", "hab": "grasslands and prairies", "habKey": "grass", "diet": "seeds and nuts", "art": "bird", "trait": "It migrates from northern hayfields all the way to southern South America and back, twice a year."}, "barn-swallow": {"name": "Barn swallow", "cat": "bird", "group": "songbird (bird)", "hab": "forest edges and clearings", "habKey": "edge", "diet": "insects and other small invertebrates", "art": "bird", "trait": "It builds a cup of mud in barns and under bridges and has a deeply forked, streaming tail."}, "tree-swallow": {"name": "Tree swallow", "cat": "bird", "group": "songbird (bird)", "hab": "wetlands and marshes", "habKey": "wetland", "diet": "insects and other small invertebrates", "art": "wetland", "trait": "Iridescent blue-green above and white below, it nests in tree holes and boxes, often near water."}, "american-mink": {"name": "American mink", "cat": "mammal", "group": "weasel (mammal)", "hab": "rivers and streams", "habKey": "river", "diet": "animals it hunts", "art": "beaver", "trait": "A glossy, semiaquatic weasel, it hunts both on land and underwater along streambanks and pond edges."}, "long-tailed-weasel": {"name": "Long-tailed weasel", "cat": "mammal", "group": "weasel (mammal)", "hab": "forest edges and clearings", "habKey": "edge", "diet": "small mammals like mice and rabbits", "art": "fox", "trait": "A small but fearless hunter, in the north it trades its brown coat for pure white in winter."}, "american-badger": {"name": "American badger", "cat": "mammal", "group": "badger (mammal)", "hab": "grasslands and prairies", "habKey": "grass", "diet": "small mammals like mice and rabbits", "art": "fox", "trait": "A powerful digger, it can tunnel through soil astonishingly fast to chase ground squirrels into their burrows."}, "fisher": {"name": "Fisher", "cat": "mammal", "group": "weasel (mammal)", "hab": "forests and woodlands", "habKey": "forest", "diet": "animals it hunts", "art": "fox", "trait": "A large forest weasel, it is one of the few predators skilled enough to regularly kill porcupines."}, "wolverine": {"name": "Wolverine", "cat": "mammal", "group": "weasel (mammal)", "hab": "cold northern tundra", "habKey": "tundra", "diet": "animals it hunts", "art": "tundra", "trait": "The largest land-dwelling weasel, it has jaws and strength out of all proportion to its size."}, "gray-fox": {"name": "Gray fox", "cat": "mammal", "group": "fox (mammal)", "hab": "forests and woodlands", "habKey": "forest", "diet": "a wide range of plant and animal foods", "art": "fox", "trait": "Unique among American dogs, it can climb trees, using hooked claws to escape danger or reach fruit."}, "swift-fox": {"name": "Swift fox", "cat": "mammal", "group": "fox (mammal)", "hab": "grasslands and prairies", "habKey": "grass", "diet": "a wide range of plant and animal foods", "art": "fox", "trait": "A cat-sized fox of the short-grass prairie, it is named for its quick, darting bursts of speed."}, "kit-fox": {"name": "Kit fox", "cat": "mammal", "group": "fox (mammal)", "hab": "deserts and dry scrub", "habKey": "desert", "diet": "animals it hunts", "art": "fox", "trait": "A tiny desert fox with enormous ears that shed body heat and pick up the faint sounds of prey."}, "ringtail": {"name": "Ringtail", "cat": "mammal", "group": "raccoon relative (mammal)", "hab": "rocky outcrops and talus", "habKey": "rocky", "diet": "a wide range of plant and animal foods", "art": "deer", "trait": "A nimble relative of the raccoon, it has a long banded tail nearly as long as its body and is a superb climber."}, "muskrat": {"name": "Muskrat", "cat": "mammal", "group": "rodent (mammal)", "hab": "wetlands and marshes", "habKey": "wetland", "diet": "water plants", "art": "beaver", "trait": "It builds dome-shaped lodges of cattails and reeds in marshes and swims with a flattened, rudder-like tail."}, "woodchuck": {"name": "Woodchuck (groundhog)", "cat": "mammal", "group": "marmot (mammal)", "hab": "meadows and open fields", "habKey": "meadow", "diet": "plants, leaves and shoots", "art": "fox", "trait": "A large burrowing ground squirrel, it fattens up in fall and sleeps through winter in true, deep hibernation."}, "yellow-bellied-marmot": {"name": "Yellow-bellied marmot", "cat": "mammal", "group": "marmot (mammal)", "hab": "rocky outcrops and talus", "habKey": "rocky", "diet": "plants, leaves and shoots", "art": "deer", "trait": "It suns itself on mountain boulders and gives a sharp whistle of alarm, earning the nickname 'whistle pig.'"}, "black-tailed-prairie-dog": {"name": "Black-tailed prairie dog", "cat": "mammal", "group": "prairie dog (mammal)", "hab": "grasslands and prairies", "habKey": "grass", "diet": "plants, leaves and shoots", "art": "fox", "trait": "It lives in vast underground 'towns' and is a keystone of the prairie whose burrows shelter many other animals."}, "thirteen-lined-ground-squirrel": {"name": "Thirteen-lined ground squirrel", "cat": "mammal", "group": "squirrel (mammal)", "hab": "grasslands and prairies", "habKey": "grass", "diet": "a wide range of plant and animal foods", "art": "fox", "trait": "Its back is striped and spotted like a tiny leopard, and it spends winter hibernating underground."}, "golden-mantled-ground-squirrel": {"name": "Golden-mantled ground squirrel", "cat": "mammal", "group": "squirrel (mammal)", "hab": "mountains and high slopes", "habKey": "mountain", "diet": "a wide range of plant and animal foods", "art": "deer", "trait": "Often mistaken for a big chipmunk, it has the chipmunk's striped body but no stripes across its face."}, "american-marten": {"name": "American marten", "cat": "mammal", "group": "weasel (mammal)", "hab": "coniferous forests", "habKey": "conifer", "diet": "small mammals like mice and rabbits", "art": "fox", "trait": "A slender, agile climber of northern conifer forests, it chases voles and squirrels through the branches and hunts on the snow in winter."}, "southern-flying-squirrel": {"name": "Southern flying squirrel", "cat": "mammal", "group": "squirrel (mammal)", "hab": "forests and woodlands", "habKey": "forest", "diet": "a wide range of plant and animal foods", "art": "fox", "trait": "Active at night, it glides from tree to tree on a furred flap of skin stretched between its legs."}, "fox-squirrel": {"name": "Fox squirrel", "cat": "mammal", "group": "squirrel (mammal)", "hab": "forests and woodlands", "habKey": "forest", "diet": "seeds and nuts", "art": "fox", "trait": "The largest tree squirrel in North America, it buries nuts one at a time, planting future trees it never returns to."}, "white-footed-mouse": {"name": "White-footed mouse", "cat": "mammal", "group": "mouse (mammal)", "hab": "forests and woodlands", "habKey": "forest", "diet": "seeds and nuts", "art": "fox", "trait": "A common woodland mouse with white feet and belly, it caches seeds and nuts for the lean months."}, "deer-mouse": {"name": "Deer mouse", "cat": "mammal", "group": "mouse (mammal)", "hab": "many habitats across North America", "habKey": "widespread", "diet": "seeds and nuts", "art": "fox", "trait": "Big-eyed and wide-ranging, this native mouse lives in nearly every habitat across North America."}, "meadow-vole": {"name": "Meadow vole", "cat": "mammal", "group": "vole (mammal)", "hab": "meadows and open fields", "habKey": "meadow", "diet": "plants, leaves and shoots", "art": "fox", "trait": "It mows tiny runways through the grass and is a crucial food source for hawks, owls, foxes and snakes."}, "eastern-mole": {"name": "Eastern mole", "cat": "mammal", "group": "mole (mammal)", "hab": "soil and leaf litter", "habKey": "soil", "diet": "insects and other small invertebrates", "art": "fox", "trait": "It spends almost its whole life underground, swimming through soil with broad, shovel-shaped front paws."}, "star-nosed-mole": {"name": "Star-nosed mole", "cat": "mammal", "group": "mole (mammal)", "hab": "wetlands and marshes", "habKey": "wetland", "diet": "insects and other small invertebrates", "art": "beaver", "trait": "A ring of 22 pink feelers on its snout helps it find food, and it is one of the fastest-eating mammals known."}, "short-tailed-shrew": {"name": "Northern short-tailed shrew", "cat": "mammal", "group": "shrew (mammal)", "hab": "forests and woodlands", "habKey": "forest", "diet": "insects and other small invertebrates", "art": "fox", "trait": "One of the very few venomous mammals, its toxic saliva can subdue prey larger than itself."}, "big-brown-bat": {"name": "Big brown bat", "cat": "mammal", "group": "bat (mammal)", "hab": "towns, parks and gardens", "habKey": "urban", "diet": "insects and other small invertebrates", "art": "fox", "trait": "A hardy, widespread bat, it often roosts in attics and barns and hunts beetles and moths after dark."}, "mexican-free-tailed-bat": {"name": "Mexican free-tailed bat", "cat": "mammal", "group": "bat (mammal)", "hab": "caves and rocky crevices", "habKey": "cave", "diet": "insects and other small invertebrates", "art": "cave", "trait": "It gathers in colonies of millions and is one of the fastest-flying mammals, reaching high speeds in level flight."}, "hoary-bat": {"name": "Hoary bat", "cat": "mammal", "group": "bat (mammal)", "hab": "forests and woodlands", "habKey": "forest", "diet": "insects and other small invertebrates", "art": "fox", "trait": "Named for its frost-tipped fur, this solitary bat migrates long distances and roosts alone in the trees."}, "snowshoe-hare": {"name": "Snowshoe hare", "cat": "mammal", "group": "hare (mammal)", "hab": "coniferous forests", "habKey": "conifer", "diet": "leaves, twigs and buds", "art": "fox", "trait": "Its huge, furry hind feet act like snowshoes, and its coat turns from brown to white with the seasons."}, "black-tailed-jackrabbit": {"name": "Black-tailed jackrabbit", "cat": "mammal", "group": "hare (mammal)", "hab": "deserts and dry scrub", "habKey": "desert", "diet": "plants, leaves and shoots", "art": "fox", "trait": "Not a rabbit but a hare, its enormous ears help it shed heat in the hot, open country where it lives."}, "mountain-goat": {"name": "Mountain goat", "cat": "mammal", "group": "hoofed mammal", "hab": "mountains and high slopes", "habKey": "mountain", "diet": "leaves, twigs and buds", "art": "deer", "trait": "With rubbery, gripping hoof pads it climbs near-vertical cliffs, living high above the treeline year round."}, "javelina": {"name": "Collared peccary (javelina)", "cat": "mammal", "group": "peccary (mammal)", "hab": "deserts and dry scrub", "habKey": "desert", "diet": "a wide range of plant and animal foods", "art": "fox", "trait": "A pig-like animal of the Southwest, it travels in tight-knit herds and marks its group with a strong scent."}, "canada-lynx": {"name": "Canada lynx", "cat": "mammal", "group": "cat (mammal)", "hab": "coniferous forests", "habKey": "conifer", "diet": "animals it hunts", "art": "fox", "trait": "With broad, furry paws like built-in snowshoes, it is a specialist hunter of the snowshoe hare."}, "western-spotted-skunk": {"name": "Western spotted skunk", "cat": "mammal", "group": "skunk (mammal)", "hab": "forest edges and clearings", "habKey": "edge", "diet": "a wide range of plant and animal foods", "art": "fox", "trait": "Smaller and more agile than the striped skunk, it does a remarkable handstand to aim its spray."}, "eastern-cottonwood": {"name": "Eastern cottonwood", "cat": "tree", "group": "cottonwood tree", "hab": "streamsides and riverbanks", "habKey": "riparian", "diet": "(makes its own food from sunlight)", "art": "oak", "trait": "A fast-growing riverside tree, it releases fluffy, cotton-like seeds that drift on the wind in early summer."}, "tulip-tree": {"name": "Tulip tree", "cat": "tree", "group": "tulip tree", "hab": "forests and woodlands", "habKey": "forest", "diet": "(makes its own food from sunlight)", "art": "oak", "trait": "One of the tallest eastern hardwoods, it lifts greenish, tulip-shaped flowers high in its crown."}, "black-walnut": {"name": "Black walnut", "cat": "tree", "group": "walnut tree", "hab": "forests and woodlands", "habKey": "forest", "diet": "(makes its own food from sunlight)", "art": "oak", "trait": "Its roots release a natural chemical called juglone that discourages many other plants from growing nearby."}, "white-ash": {"name": "White ash", "cat": "tree", "group": "ash tree", "hab": "forests and woodlands", "habKey": "forest", "diet": "(makes its own food from sunlight)", "art": "oak", "trait": "Once a common shade and baseball-bat tree, it is now under siege from the invasive emerald ash borer beetle."}, "american-elm": {"name": "American elm", "cat": "tree", "group": "elm tree", "hab": "towns, parks and gardens", "habKey": "urban", "diet": "(makes its own food from sunlight)", "art": "oak", "trait": "Its graceful vase shape once arched over city streets until Dutch elm disease swept many of them away."}, "eastern-redbud": {"name": "Eastern redbud", "cat": "tree", "group": "redbud tree", "hab": "forest edges and clearings", "habKey": "edge", "diet": "(makes its own food from sunlight)", "art": "oak", "trait": "Clusters of pink-purple flowers burst directly from its bare branches and trunk in early spring."}, "flowering-dogwood": {"name": "Flowering dogwood", "cat": "tree", "group": "dogwood tree", "hab": "the forest understory", "habKey": "understory", "diet": "(makes its own food from sunlight)", "art": "oak", "trait": "Its showy spring 'petals' are really leaf-like bracts surrounding the tiny true flowers in the center."}, "sweetgum": {"name": "Sweetgum", "cat": "tree", "group": "sweetgum tree", "hab": "forests and woodlands", "habKey": "forest", "diet": "(makes its own food from sunlight)", "art": "oak", "trait": "Its star-shaped leaves blaze red and purple in fall, and it drops hard, spiky seed balls."}, "balsam-fir": {"name": "Balsam fir", "cat": "tree", "group": "fir tree", "hab": "coniferous forests", "habKey": "conifer", "diet": "(makes its own food from sunlight)", "art": "mountain", "trait": "Prized as a Christmas tree, its smooth bark holds blisters of fragrant, sticky resin."}, "red-spruce": {"name": "Red spruce", "cat": "tree", "group": "spruce tree", "hab": "mountains and high slopes", "habKey": "mountain", "diet": "(makes its own food from sunlight)", "art": "mountain", "trait": "A slow-growing evergreen of the high Appalachian and northeastern ridgetops."}, "eastern-red-cedar": {"name": "Eastern red cedar", "cat": "tree", "group": "cedar tree", "hab": "forest edges and clearings", "habKey": "edge", "diet": "(makes its own food from sunlight)", "art": "oak", "trait": "Despite its name it is a juniper, bearing dusty-blue, berry-like cones that many birds eat."}, "longleaf-pine": {"name": "Longleaf pine", "cat": "tree", "group": "pine tree", "hab": "coniferous forests", "habKey": "conifer", "diet": "(makes its own food from sunlight)", "art": "mountain", "trait": "It depends on fire and spends its first years as a grass-like tuft before suddenly shooting skyward."}, "ponderosa-pine": {"name": "Ponderosa pine", "cat": "tree", "group": "pine tree", "hab": "mountains and high slopes", "habKey": "mountain", "diet": "(makes its own food from sunlight)", "art": "mountain", "trait": "Its thick, puzzle-piece bark resists fire and smells of vanilla or butterscotch when warmed by the sun."}, "lodgepole-pine": {"name": "Lodgepole pine", "cat": "tree", "group": "pine tree", "hab": "mountains and high slopes", "habKey": "mountain", "diet": "(makes its own food from sunlight)", "art": "mountain", "trait": "Many of its cones are sealed shut with resin and only pop open in the heat of a forest fire."}, "western-red-cedar": {"name": "Western red cedar", "cat": "tree", "group": "cedar tree", "hab": "moist shady forests", "habKey": "wetforest", "diet": "(makes its own food from sunlight)", "art": "oak", "trait": "A giant of the Pacific Northwest, its rot-resistant wood was carved into canoes and totem poles."}, "honey-locust": {"name": "Honey locust", "cat": "tree", "group": "locust tree", "hab": "forest edges and clearings", "habKey": "edge", "diet": "(makes its own food from sunlight)", "art": "oak", "trait": "Wild trees guard their trunks and limbs with clusters of long, branching thorns."}, "black-cherry": {"name": "Black cherry", "cat": "tree", "group": "cherry tree", "hab": "forests and woodlands", "habKey": "forest", "diet": "(makes its own food from sunlight)", "art": "oak", "trait": "Drooping white flower clusters become dark cherries that feed many birds and mammals."}, "sassafras": {"name": "Sassafras", "cat": "tree", "group": "sassafras tree", "hab": "forest edges and clearings", "habKey": "edge", "diet": "(makes its own food from sunlight)", "art": "oak", "trait": "A single tree can carry three leaf shapes at once: oval, two-lobed 'mitten,' and three-lobed."}, "pawpaw": {"name": "Pawpaw", "cat": "tree", "group": "pawpaw tree", "hab": "the forest understory", "habKey": "understory", "diet": "(makes its own food from sunlight)", "art": "oak", "trait": "It bears the largest edible fruit native to North America, with a soft, custardy, tropical flavor."}, "wild-bergamot": {"name": "Wild bergamot", "cat": "wildflower", "group": "bergamot wildflower", "hab": "meadows and open fields", "habKey": "meadow", "diet": "(makes its own food from sunlight)", "art": "meadow", "trait": "Its ragged lavender flower heads smell strongly of mint and draw bees, butterflies and hummingbirds."}, "butterfly-milkweed": {"name": "Butterfly milkweed", "cat": "wildflower", "group": "orange milkweed wildflower", "hab": "meadows and open fields", "habKey": "meadow", "diet": "(makes its own food from sunlight)", "art": "meadow", "trait": "A brilliant-orange milkweed whose flowers swarm with butterflies and whose leaves feed monarch caterpillars."}, "showy-milkweed": {"name": "Showy milkweed", "cat": "wildflower", "group": "milkweed wildflower", "hab": "grasslands and prairies", "habKey": "grass", "diet": "(makes its own food from sunlight)", "art": "meadow", "trait": "Star-shaped pink flower clusters give way to pods of silk-tufted seeds; its leaves feed western monarchs."}, "new-england-aster": {"name": "New England aster", "cat": "wildflower", "group": "purple aster wildflower", "hab": "meadows and open fields", "habKey": "meadow", "diet": "(makes its own food from sunlight)", "art": "meadow", "trait": "Clouds of purple, daisy-like blooms with gold centers feed pollinators late into the fall."}, "common-yarrow": {"name": "Common yarrow", "cat": "wildflower", "group": "yarrow wildflower", "hab": "meadows and open fields", "habKey": "meadow", "diet": "(makes its own food from sunlight)", "art": "meadow", "trait": "Flat-topped clusters of tiny white flowers rise above feathery leaves long used to slow bleeding."}, "wild-lupine": {"name": "Wild lupine", "cat": "wildflower", "group": "lupine wildflower", "hab": "grasslands and prairies", "habKey": "grass", "diet": "(makes its own food from sunlight)", "art": "meadow", "trait": "Spikes of blue pea-flowers; its leaves are the only food of the rare Karner blue butterfly's caterpillars."}, "blue-flag-iris": {"name": "Blue flag iris", "cat": "wildflower", "group": "wild iris wildflower", "hab": "wetlands and marshes", "habKey": "wetland", "diet": "(makes its own food from sunlight)", "art": "wildflower", "trait": "A native iris of marsh edges with violet-blue flowers veined in yellow."}, "wild-columbine": {"name": "Wild columbine", "cat": "wildflower", "group": "columbine wildflower", "hab": "rocky outcrops and talus", "habKey": "rocky", "diet": "(makes its own food from sunlight)", "art": "wildflower", "trait": "Nodding red-and-yellow flowers with backward-pointing nectar spurs that hummingbirds probe."}, "bloodroot": {"name": "Bloodroot", "cat": "wildflower", "group": "woodland wildflower", "hab": "forests and woodlands", "habKey": "forest", "diet": "(makes its own food from sunlight)", "art": "wildflower", "trait": "An early-spring forest flower whose broken root oozes a red-orange sap."}, "mayapple": {"name": "Mayapple", "cat": "wildflower", "group": "woodland wildflower", "hab": "forests and woodlands", "habKey": "forest", "diet": "(makes its own food from sunlight)", "art": "wildflower", "trait": "Pairs of umbrella-like leaves hide one white flower; only its ripe fruit is edible, the rest is toxic."}, "trout-lily": {"name": "Trout lily", "cat": "wildflower", "group": "spring lily wildflower", "hab": "forests and woodlands", "habKey": "forest", "diet": "(makes its own food from sunlight)", "art": "wildflower", "trait": "Mottled leaves and a nodding yellow lily appear briefly before the forest canopy leafs out."}, "virginia-bluebells": {"name": "Virginia bluebells", "cat": "wildflower", "group": "woodland wildflower", "hab": "moist shady forests", "habKey": "wetforest", "diet": "(makes its own food from sunlight)", "art": "wildflower", "trait": "Pink buds open into nodding, bell-shaped blue flowers across spring floodplain woods."}, "wild-geranium": {"name": "Wild geranium", "cat": "wildflower", "group": "woodland wildflower", "hab": "forests and woodlands", "habKey": "forest", "diet": "(makes its own food from sunlight)", "art": "wildflower", "trait": "Its ripe seed capsules curl back and fling the seeds away like tiny catapults."}, "joe-pye-weed": {"name": "Joe-pye weed", "cat": "wildflower", "group": "tall wildflower", "hab": "wetlands and marshes", "habKey": "wetland", "diet": "(makes its own food from sunlight)", "art": "wildflower", "trait": "Towering domes of dusty-pink flowers buzz with late-summer butterflies and bees."}, "jack-in-the-pulpit": {"name": "Jack-in-the-pulpit", "cat": "wildflower", "group": "woodland wildflower", "hab": "moist shady forests", "habKey": "wetforest", "diet": "(makes its own food from sunlight)", "art": "wildflower", "trait": "A hooded green-and-purple 'pulpit' shelters a spike that later forms a cluster of red berries."}, "evening-primrose": {"name": "Evening primrose", "cat": "wildflower", "group": "wildflower", "hab": "forest edges and clearings", "habKey": "edge", "diet": "(makes its own food from sunlight)", "art": "wildflower", "trait": "Its lemon-yellow flowers open at dusk and are pollinated by night-flying moths."}, "spicebush": {"name": "Spicebush", "cat": "shrub", "group": "native shrub", "hab": "moist shady forests", "habKey": "wetforest", "diet": "(makes its own food from sunlight)", "art": "forest", "trait": "Crush a leaf and it smells of spice; its red berries and leaves feed the spicebush swallowtail."}, "witch-hazel": {"name": "Witch-hazel", "cat": "shrub", "group": "native shrub", "hab": "forests and woodlands", "habKey": "forest", "diet": "(makes its own food from sunlight)", "art": "forest", "trait": "It blooms with spidery yellow flowers in late fall as its leaves drop, then shoots its seeds out."}, "american-elderberry": {"name": "American elderberry", "cat": "shrub", "group": "elderberry shrub", "hab": "wetlands and marshes", "habKey": "wetland", "diet": "(makes its own food from sunlight)", "art": "forest", "trait": "Flat clusters of tiny white flowers become dark purple berries used in jelly and pie."}, "buttonbush": {"name": "Buttonbush", "cat": "shrub", "group": "wetland shrub", "hab": "wetlands and marshes", "habKey": "wetland", "diet": "(makes its own food from sunlight)", "art": "forest", "trait": "A water-loving shrub with spherical, pincushion-like white flower balls that draw butterflies."}, "staghorn-sumac": {"name": "Staghorn sumac", "cat": "shrub", "group": "sumac shrub", "hab": "forest edges and clearings", "habKey": "edge", "diet": "(makes its own food from sunlight)", "art": "forest", "trait": "Velvety, antler-like branches end in fuzzy red berry cones that last through winter."}, "winterberry": {"name": "Winterberry", "cat": "shrub", "group": "holly shrub", "hab": "wetlands and marshes", "habKey": "wetland", "diet": "(makes its own food from sunlight)", "art": "forest", "trait": "A native deciduous holly whose bare winter branches glow with bright red berries."}, "mountain-laurel": {"name": "Mountain laurel", "cat": "shrub", "group": "evergreen shrub", "hab": "forests and woodlands", "habKey": "forest", "diet": "(makes its own food from sunlight)", "art": "forest", "trait": "Its spring-loaded flower stamens flick pollen onto visiting bees as they land."}, "american-beautyberry": {"name": "American beautyberry", "cat": "shrub", "group": "native shrub", "hab": "forest edges and clearings", "habKey": "edge", "diet": "(makes its own food from sunlight)", "art": "forest", "trait": "Tight rings of vivid magenta-purple berries clasp its stems in autumn."}, "creosote-bush": {"name": "Creosote bush", "cat": "shrub", "group": "desert shrub", "hab": "deserts and dry scrub", "habKey": "desert", "diet": "(makes its own food from sunlight)", "art": "forest", "trait": "A desert shrub that smells of rain; some clonal rings are among the oldest living things on Earth."}, "greenleaf-manzanita": {"name": "Greenleaf manzanita", "cat": "shrub", "group": "manzanita shrub", "hab": "mountains and high slopes", "habKey": "mountain", "diet": "(makes its own food from sunlight)", "art": "forest", "trait": "Smooth red-brown bark and crooked branches; its berries ('little apples') feed wildlife."}, "indiangrass": {"name": "Indiangrass", "cat": "grass", "group": "prairie grass", "hab": "grasslands and prairies", "habKey": "grass", "diet": "(makes its own food from sunlight)", "art": "meadow", "trait": "A tall prairie grass with golden, plume-like seed heads that shimmer in autumn light."}, "sideoats-grama": {"name": "Sideoats grama", "cat": "grass", "group": "grama grass", "hab": "grasslands and prairies", "habKey": "grass", "diet": "(makes its own food from sunlight)", "art": "meadow", "trait": "Small oat-like seed spikes dangle along just one side of each arching stem."}, "soft-rush": {"name": "Soft rush", "cat": "grass", "group": "wetland rush", "hab": "wetlands and marshes", "habKey": "wetland", "diet": "(makes its own food from sunlight)", "art": "grassland", "trait": "Forms green clumps of round, wiry stems; rushes are round where sedges are three-sided."}, "tussock-sedge": {"name": "Tussock sedge", "cat": "grass", "group": "marsh sedge", "hab": "wetlands and marshes", "habKey": "wetland", "diet": "(makes its own food from sunlight)", "art": "grassland", "trait": "Builds raised clumps ('tussocks') in marshes; its stem is solid and triangular in cross-section."}, "maidenhair-fern": {"name": "Maidenhair fern", "cat": "fern or moss", "group": "woodland fern", "hab": "moist shady forests", "habKey": "wetforest", "diet": "(makes its own food from sunlight)", "art": "fern", "trait": "Delicate fan-shaped leaflets spread on shiny black stems across moist, shady woods."}, "christmas-fern": {"name": "Christmas fern", "cat": "fern or moss", "group": "evergreen fern", "hab": "forests and woodlands", "habKey": "forest", "diet": "(makes its own food from sunlight)", "art": "fern", "trait": "Stays green through winter, and each leaflet has a small 'toe' like a Christmas stocking."}, "royal-fern": {"name": "Royal fern", "cat": "fern or moss", "group": "large fern", "hab": "wetlands and marshes", "habKey": "wetland", "diet": "(makes its own food from sunlight)", "art": "fern", "trait": "A big fern of swampy ground whose fertile frond tips look like clusters of flowers."}, "field-horsetail": {"name": "Field horsetail", "cat": "fern or moss", "group": "horsetail spore plant", "hab": "streamsides and riverbanks", "habKey": "riparian", "diet": "(makes its own food from sunlight)", "art": "fern", "trait": "A living fossil with jointed, hollow stems; its ancient relatives helped form today's coal."}, "haircap-moss": {"name": "Haircap moss", "cat": "fern or moss", "group": "cushion moss", "hab": "forests and woodlands", "habKey": "forest", "diet": "(makes its own food from sunlight)", "art": "fern", "trait": "One of the tallest mosses, forming star-like rosettes of stiff little leaves."}, "princess-pine": {"name": "Princess pine", "cat": "fern or moss", "group": "clubmoss", "hab": "forests and woodlands", "habKey": "forest", "diet": "(makes its own food from sunlight)", "art": "fern", "trait": "A tiny evergreen clubmoss that looks like a miniature pine tree carpeting the forest floor."}, "eastern-ratsnake": {"name": "Eastern ratsnake", "cat": "reptile", "group": "ratsnake (reptile)", "hab": "forests and woodlands", "habKey": "forest", "diet": "small mammals like mice and rabbits", "art": "reptile", "trait": "A large, strong climber that squeezes rodents and birds; it is harmless to people."}, "northern-watersnake": {"name": "Northern watersnake", "cat": "reptile", "group": "watersnake (reptile)", "hab": "wetlands and marshes", "habKey": "wetland", "diet": "frogs, insects and other small prey", "art": "pond", "trait": "A nonvenomous water snake often mistaken for a cottonmouth as it hunts fish and frogs."}, "eastern-hognose-snake": {"name": "Eastern hognose snake", "cat": "reptile", "group": "hognose snake (reptile)", "hab": "forest edges and clearings", "habKey": "edge", "diet": "frogs, insects and other small prey", "art": "reptile", "trait": "When alarmed it flattens its neck and hisses, then rolls over and plays dead."}, "ringneck-snake": {"name": "Ring-necked snake", "cat": "reptile", "group": "snake (reptile)", "hab": "forests and woodlands", "habKey": "forest", "diet": "insects and other small invertebrates", "art": "reptile", "trait": "A small, secretive snake with a bright yellow-orange belly and a matching neck ring."}, "eastern-milksnake": {"name": "Eastern milksnake", "cat": "reptile", "group": "milk snake (reptile)", "hab": "forest edges and clearings", "habKey": "edge", "diet": "small mammals like mice and rabbits", "art": "reptile", "trait": "Its red, black and yellow bands mimic a venomous coral snake, but it is completely harmless."}, "eastern-coral-snake": {"name": "Eastern coral snake", "cat": "reptile", "group": "coral snake (reptile)", "hab": "forests and woodlands", "habKey": "forest", "diet": "animals it hunts", "art": "reptile", "trait": "A venomous snake where red bands touch yellow: 'red touches yellow, kill a fellow.'"}, "timber-rattlesnake": {"name": "Timber rattlesnake", "cat": "reptile", "group": "rattlesnake (reptile)", "hab": "forests and woodlands", "habKey": "forest", "diet": "small mammals like mice and rabbits", "art": "reptile", "trait": "A venomous pit viper of eastern woods that buzzes its tail in warning before it strikes."}, "copperhead": {"name": "Copperhead", "cat": "reptile", "group": "copperhead snake (reptile)", "hab": "forests and woodlands", "habKey": "forest", "diet": "small mammals like mice and rabbits", "art": "reptile", "trait": "A venomous pit viper whose hourglass coppery bands vanish against fallen leaves."}, "common-kingsnake": {"name": "Common kingsnake", "cat": "reptile", "group": "kingsnake (reptile)", "hab": "forest edges and clearings", "habKey": "edge", "diet": "animals it hunts", "art": "reptile", "trait": "A glossy snake that even eats venomous snakes, being largely immune to their venom."}, "rough-green-snake": {"name": "Rough green snake", "cat": "reptile", "group": "green snake (reptile)", "hab": "forest edges and clearings", "habKey": "edge", "diet": "insects and other small invertebrates", "art": "reptile", "trait": "A slender, bright-green snake that glides through shrubs hunting insects and spiders."}, "six-lined-racerunner": {"name": "Six-lined racerunner", "cat": "reptile", "group": "racerunner lizard (reptile)", "hab": "grasslands and prairies", "habKey": "grass", "diet": "insects and other small invertebrates", "art": "reptile", "trait": "A fast, striped lizard that darts across sandy ground in sudden bursts of speed."}, "five-lined-skink": {"name": "Five-lined skink", "cat": "reptile", "group": "skink (reptile)", "hab": "forests and woodlands", "habKey": "forest", "diet": "insects and other small invertebrates", "art": "reptile", "trait": "Young skinks flash an electric-blue tail that can snap off to distract a predator."}, "western-fence-lizard": {"name": "Western fence lizard", "cat": "reptile", "group": "fence lizard (reptile)", "hab": "rocky outcrops and talus", "habKey": "rocky", "diet": "insects and other small invertebrates", "art": "reptile", "trait": "Males do 'push-ups' to flash blue belly patches; the lizard may even lower Lyme disease in ticks."}, "eastern-collared-lizard": {"name": "Eastern collared lizard", "cat": "reptile", "group": "collared lizard (reptile)", "hab": "deserts and dry scrub", "habKey": "desert", "diet": "insects and other small invertebrates", "art": "desert", "trait": "A boldly collared lizard that can sprint on its hind legs like a tiny dinosaur."}, "gila-monster": {"name": "Gila monster", "cat": "reptile", "group": "beaded lizard (reptile)", "hab": "deserts and dry scrub", "habKey": "desert", "diet": "animals it hunts", "art": "desert", "trait": "One of the few venomous lizards, slow and beaded, storing fat in its thick tail."}, "eastern-musk-turtle": {"name": "Eastern musk turtle", "cat": "reptile", "group": "musk turtle (reptile)", "hab": "wetlands and marshes", "habKey": "wetland", "diet": "a wide range of plant and animal foods", "art": "pond", "trait": "A small turtle that releases a musky smell when handled and walks along pond bottoms."}, "red-eared-slider": {"name": "Red-eared slider", "cat": "reptile", "group": "slider turtle (reptile)", "hab": "wetlands and marshes", "habKey": "wetland", "diet": "a wide range of plant and animal foods", "art": "pond", "trait": "Named for the red stripe behind each eye, it basks in stacks on logs."}, "wood-turtle": {"name": "Wood turtle", "cat": "reptile", "group": "wood turtle (reptile)", "hab": "rivers and streams", "habKey": "river", "diet": "a wide range of plant and animal foods", "art": "pond", "trait": "Its shell looks carved from wood, and it stomps the ground to lure earthworms up."}, "spiny-softshell-turtle": {"name": "Spiny softshell turtle", "cat": "reptile", "group": "softshell turtle (reptile)", "hab": "rivers and streams", "habKey": "river", "diet": "animals it hunts", "art": "pond", "trait": "A flat, pancake-like turtle with a leathery shell and a snorkel-like nose."}, "gopher-tortoise": {"name": "Gopher tortoise", "cat": "reptile", "group": "tortoise (reptile)", "hab": "grasslands and prairies", "habKey": "grass", "diet": "plants, leaves and shoots", "art": "reptile", "trait": "Its deep burrows shelter hundreds of other species, making it a keystone of southern pinelands."}, "ornate-box-turtle": {"name": "Ornate box turtle", "cat": "reptile", "group": "box turtle (reptile)", "hab": "grasslands and prairies", "habKey": "grass", "diet": "a wide range of plant and animal foods", "art": "reptile", "trait": "A land turtle of the prairies with yellow lines radiating across a high-domed shell."}, "gray-treefrog": {"name": "Gray treefrog", "cat": "tree", "group": "treefrog (amphibian)", "hab": "forests and woodlands", "habKey": "forest", "diet": "insects and other small invertebrates", "art": "oak", "trait": "It can shift from gray to green and grips bark with sticky, expandable toe pads."}, "green-frog": {"name": "Green frog", "cat": "amphibian", "group": "frog (amphibian)", "hab": "lakes and ponds", "habKey": "lake", "diet": "insects and other small invertebrates", "art": "pond", "trait": "Its call sounds like a loose banjo string plucked once over the pond."}, "northern-leopard-frog": {"name": "Northern leopard frog", "cat": "amphibian", "group": "leopard frog (amphibian)", "hab": "wetlands and marshes", "habKey": "wetland", "diet": "insects and other small invertebrates", "art": "frog", "trait": "Green and patterned with rows of dark, light-ringed spots like a leopard's coat."}, "pickerel-frog": {"name": "Pickerel frog", "cat": "amphibian", "group": "frog (amphibian)", "hab": "wetlands and marshes", "habKey": "wetland", "diet": "insects and other small invertebrates", "art": "frog", "trait": "Two rows of square chocolate spots mark its back, and its skin tastes foul to predators."}, "northern-cricket-frog": {"name": "Northern cricket frog", "cat": "amphibian", "group": "frog (amphibian)", "hab": "wetlands and marshes", "habKey": "wetland", "diet": "insects and other small invertebrates", "art": "frog", "trait": "A thumbnail-sized frog whose clicking call sounds like two pebbles tapped together."}, "fowlers-toad": {"name": "Fowler's toad", "cat": "amphibian", "group": "toad (amphibian)", "hab": "forest edges and clearings", "habKey": "edge", "diet": "insects and other small invertebrates", "art": "frog", "trait": "A warty toad of sandy ground with a short, nasal, bleating call."}, "eastern-spadefoot": {"name": "Eastern spadefoot", "cat": "amphibian", "group": "spadefoot toad (amphibian)", "hab": "forest edges and clearings", "habKey": "edge", "diet": "insects and other small invertebrates", "art": "frog", "trait": "It digs backward into the soil with spade-like hind feet and waits underground for heavy rain."}, "eastern-red-backed-salamander": {"name": "Eastern red-backed salamander", "cat": "amphibian", "group": "salamander (amphibian)", "hab": "forests and woodlands", "habKey": "forest", "diet": "insects and other small invertebrates", "art": "frog", "trait": "A lungless salamander that breathes through its skin and never needs to enter water."}, "tiger-salamander": {"name": "Tiger salamander", "cat": "amphibian", "group": "salamander (amphibian)", "hab": "grasslands and prairies", "habKey": "grass", "diet": "insects and other small invertebrates", "art": "frog", "trait": "One of the largest land salamanders, boldly blotched with yellow on black."}, "marbled-salamander": {"name": "Marbled salamander", "cat": "amphibian", "group": "salamander (amphibian)", "hab": "forests and woodlands", "habKey": "forest", "diet": "insects and other small invertebrates", "art": "frog", "trait": "Silvery-white bands cross its black body, and it guards its eggs in a dry nest until rains come."}, "mudpuppy": {"name": "Mudpuppy", "cat": "amphibian", "group": "mudpuppy salamander (amphibian)", "hab": "rivers and streams", "habKey": "river", "diet": "animals it hunts", "art": "pond", "trait": "A fully aquatic salamander that keeps frilly red gills for its entire life."}, "rough-skinned-newt": {"name": "Rough-skinned newt", "cat": "amphibian", "group": "newt (amphibian)", "hab": "moist shady forests", "habKey": "wetforest", "diet": "insects and other small invertebrates", "art": "frog", "trait": "Its skin carries one of the strongest natural toxins known, advertised by a bright orange belly."}, "smallmouth-bass": {"name": "Smallmouth bass", "cat": "freshwater fish", "group": "bass (fish)", "hab": "rivers and streams", "habKey": "river", "diet": "animals it hunts", "art": "fish", "trait": "A hard-fighting bronze bass of cool, rocky streams and clear lakes."}, "brown-trout": {"name": "Brown trout", "cat": "freshwater fish", "group": "trout (fish)", "hab": "rivers and streams", "habKey": "river", "diet": "animals it hunts", "art": "fish", "trait": "Wary and golden-brown with red and black spots, it was brought to America from Europe."}, "lake-trout": {"name": "Lake trout", "cat": "freshwater fish", "group": "trout (fish)", "hab": "lakes and ponds", "habKey": "lake", "diet": "fish and other water animals", "art": "fish", "trait": "A deep, cold-water char that grows large and very slowly in northern lakes."}, "cutthroat-trout": {"name": "Cutthroat trout", "cat": "freshwater fish", "group": "trout (fish)", "hab": "rivers and streams", "habKey": "river", "diet": "insects and other small invertebrates", "art": "fish", "trait": "Named for the red-orange slash beneath its jaw, it is the native trout of the West."}, "yellow-perch": {"name": "Yellow perch", "cat": "freshwater fish", "group": "perch (fish)", "hab": "lakes and ponds", "habKey": "lake", "diet": "insects and other small invertebrates", "art": "fish", "trait": "Golden-yellow with dark vertical bars, it roams lakes in schools and is a favorite panfish."}, "walleye": {"name": "Walleye", "cat": "freshwater fish", "group": "perch (fish)", "hab": "lakes and ponds", "habKey": "lake", "diet": "fish and other water animals", "art": "fish", "trait": "Its large, glassy eyes gather dim light, letting it hunt at dawn, dusk and after dark."}, "northern-pike": {"name": "Northern pike", "cat": "freshwater fish", "group": "pike (fish)", "hab": "lakes and ponds", "habKey": "lake", "diet": "fish and other water animals", "art": "fish", "trait": "A long, toothy ambush hunter marked with rows of light, bean-shaped spots."}, "muskellunge": {"name": "Muskellunge", "cat": "freshwater fish", "group": "pike (fish)", "hab": "lakes and ponds", "habKey": "lake", "diet": "fish and other water animals", "art": "fish", "trait": "The largest pike, a rare 'fish of ten thousand casts' that lurks among weed beds."}, "chain-pickerel": {"name": "Chain pickerel", "cat": "freshwater fish", "group": "pike (fish)", "hab": "wetlands and marshes", "habKey": "wetland", "diet": "fish and other water animals", "art": "fish", "trait": "A small pike wearing a chain-link pattern, waiting motionless in weedy shallows."}, "black-crappie": {"name": "Black crappie", "cat": "freshwater fish", "group": "crappie (fish)", "hab": "lakes and ponds", "habKey": "lake", "diet": "insects and other small invertebrates", "art": "fish", "trait": "A silvery, black-speckled panfish that schools around sunken brush and timber."}, "pumpkinseed": {"name": "Pumpkinseed", "cat": "freshwater fish", "group": "sunfish (fish)", "hab": "lakes and ponds", "habKey": "lake", "diet": "insects and other small invertebrates", "art": "fish", "trait": "A jewel-colored sunfish with a bright orange spot on the edge of its ear flap."}, "green-sunfish": {"name": "Green sunfish", "cat": "freshwater fish", "group": "sunfish (fish)", "hab": "lakes and ponds", "habKey": "lake", "diet": "insects and other small invertebrates", "art": "fish", "trait": "A tough, big-mouthed sunfish that survives warm, low-oxygen water where others can't."}, "flathead-catfish": {"name": "Flathead catfish", "cat": "freshwater fish", "group": "catfish (fish)", "hab": "rivers and streams", "habKey": "river", "diet": "animals it hunts", "art": "fish", "trait": "A large, flat-headed catfish that prowls river bottoms hunting live prey at night."}, "blue-catfish": {"name": "Blue catfish", "cat": "freshwater fish", "group": "catfish (fish)", "hab": "rivers and streams", "habKey": "river", "diet": "a wide range of plant and animal foods", "art": "fish", "trait": "The largest catfish in North America, recognized by its deeply forked tail."}, "common-carp": {"name": "Common carp", "cat": "freshwater fish", "group": "carp (fish)", "hab": "lakes and ponds", "habKey": "lake", "diet": "a wide range of plant and animal foods", "art": "fish", "trait": "An introduced bottom-feeder that roots up mud and can survive in poor water."}, "johnny-darter": {"name": "Johnny darter", "cat": "freshwater fish", "group": "darter (fish)", "hab": "rivers and streams", "habKey": "river", "diet": "insects and other small invertebrates", "art": "fish", "trait": "A tiny bottom fish that perches on its fins and darts between stones."}, "rainbow-darter": {"name": "Rainbow darter", "cat": "freshwater fish", "group": "darter (fish)", "hab": "rivers and streams", "habKey": "river", "diet": "insects and other small invertebrates", "art": "fish", "trait": "Males blaze with blue and orange bars in spring; its presence signals clean, rocky water."}, "longnose-gar": {"name": "Longnose gar", "cat": "freshwater fish", "group": "gar (fish)", "hab": "rivers and streams", "habKey": "river", "diet": "fish and other water animals", "art": "fish", "trait": "An ancient fish armored in hard, diamond-shaped scales with a long, tooth-filled snout."}, "bowfin": {"name": "Bowfin", "cat": "freshwater fish", "group": "bowfin (fish)", "hab": "wetlands and marshes", "habKey": "wetland", "diet": "animals it hunts", "art": "fish", "trait": "A living-fossil predator that can gulp air at the surface to survive stagnant water."}, "american-eel": {"name": "American eel", "cat": "freshwater fish", "group": "eel (fish)", "hab": "rivers and streams", "habKey": "river", "diet": "animals it hunts", "art": "fish", "trait": "It hatches far out in the Atlantic and migrates thousands of miles to live in fresh water."}, "giant-puffball": {"name": "Giant puffball", "cat": "fungus or lichen", "group": "puffball fungus", "hab": "meadows and open fields", "habKey": "meadow", "diet": "(feeds on dead matter)", "art": "mushroom", "trait": "A white ball that can swell as large as a soccer ball, then puffs out trillions of spores."}, "destroying-angel": {"name": "Destroying angel", "cat": "fungus or lichen", "group": "amanita mushroom (toadstool)", "hab": "forests and woodlands", "habKey": "forest", "diet": "", "art": "mushroom", "trait": "A pure-white woodland mushroom that is among the deadliest poisonous fungi in North America."}, "king-bolete": {"name": "King bolete", "cat": "fungus or lichen", "group": "bolete mushroom", "hab": "coniferous forests", "habKey": "conifer", "diet": "", "art": "mushroom", "trait": "A stout mushroom with a spongy layer of pores, not gills, beneath its cap; it partners with tree roots."}, "chicken-of-the-woods": {"name": "Chicken of the woods", "cat": "fungus or lichen", "group": "bracket fungus", "hab": "forests and woodlands", "habKey": "forest", "diet": "(feeds on dead matter)", "art": "mushroom", "trait": "Vivid orange-and-yellow shelves grow in overlapping fans on logs and trunks."}, "hen-of-the-woods": {"name": "Hen of the woods", "cat": "fungus or lichen", "group": "bracket fungus", "hab": "forests and woodlands", "habKey": "forest", "diet": "(feeds on dead matter)", "art": "mushroom", "trait": "Big, ruffled clusters sprout at the base of oaks, layered like a sitting hen's feathers."}, "artist-conk": {"name": "Artist's conk", "cat": "fungus or lichen", "group": "bracket fungus (conk)", "hab": "forests and woodlands", "habKey": "forest", "diet": "(feeds on dead matter)", "art": "mushroom", "trait": "Its flat white underside bruises brown when scratched, so people can draw on it like a canvas."}, "birds-nest-fungus": {"name": "Bird's nest fungus", "cat": "fungus or lichen", "group": "cup fungus", "hab": "soil and leaf litter", "habKey": "soil", "diet": "(feeds on dead matter)", "art": "mushroom", "trait": "Tiny cups hold egg-like packets of spores that raindrops splash out to spread them."}, "earthstar": {"name": "Earthstar", "cat": "fungus or lichen", "group": "puffball fungus", "hab": "forests and woodlands", "habKey": "forest", "diet": "(feeds on dead matter)", "art": "mushroom", "trait": "Its outer skin splits open into a star that props up a central spore sac."}, "common-stinkhorn": {"name": "Common stinkhorn", "cat": "fungus or lichen", "group": "stinkhorn fungus", "hab": "soil and leaf litter", "habKey": "soil", "diet": "(feeds on dead matter)", "art": "mushroom", "trait": "It oozes a foul-smelling slime that lures flies, which then carry its spores away."}, "jack-o-lantern": {"name": "Jack-o'-lantern mushroom", "cat": "fungus or lichen", "group": "gilled mushroom (toadstool)", "hab": "forests and woodlands", "habKey": "forest", "diet": "(feeds on dead matter)", "art": "mushroom", "trait": "This poisonous orange mushroom's gills can glow faintly green in the dark."}, "honey-fungus": {"name": "Honey fungus", "cat": "fungus or lichen", "group": "gilled mushroom", "hab": "forests and woodlands", "habKey": "forest", "diet": "(feeds on dead matter)", "art": "mushroom", "trait": "Its underground threads can spread for kilometers, forming some of the largest organisms on Earth."}, "lions-mane": {"name": "Lion's mane", "cat": "fungus or lichen", "group": "tooth fungus (mushroom)", "hab": "forests and woodlands", "habKey": "forest", "diet": "(feeds on dead matter)", "art": "mushroom", "trait": "It cascades from logs in white spines like a frozen waterfall or a shaggy mane."}, "old-mans-beard": {"name": "Old man's beard", "cat": "fungus or lichen", "group": "beard lichen", "hab": "coniferous forests", "habKey": "conifer", "diet": "", "art": "mushroom", "trait": "A pale, stringy lichen that drapes from branches and grows only where the air is clean."}, "lungwort-lichen": {"name": "Lungwort lichen", "cat": "fungus or lichen", "group": "leaf lichen", "hab": "moist shady forests", "habKey": "wetforest", "diet": "", "art": "mushroom", "trait": "Its broad green lobes look like lung tissue, and it captures nitrogen from the air."}, "rock-tripe": {"name": "Rock tripe", "cat": "rock", "group": "rock lichen", "hab": "rocky outcrops and talus", "habKey": "rocky", "diet": "", "art": "mineral", "trait": "A leathery lichen that clings to bare cliff faces by a single central anchor point."}, "common-greenshield": {"name": "Common greenshield lichen", "cat": "fungus or lichen", "group": "shield lichen", "hab": "forests and woodlands", "habKey": "forest", "diet": "", "art": "mushroom", "trait": "A flat, pale-green lichen that patches tree bark in spreading circular crusts."}, "black-swallowtail": {"name": "Black swallowtail", "cat": "insect", "group": "swallowtail butterfly", "hab": "meadows and open fields", "habKey": "meadow", "diet": "flower nectar", "art": "butterfly", "trait": "Its green-and-black caterpillars feed on parsley, dill and carrot tops in gardens."}, "spicebush-swallowtail": {"name": "Spicebush swallowtail", "cat": "insect", "group": "swallowtail butterfly", "hab": "forests and woodlands", "habKey": "forest", "diet": "flower nectar", "art": "butterfly", "trait": "Its caterpillar has large false eyespots and curls inside a folded leaf, mimicking a snake."}, "painted-lady": {"name": "Painted lady", "cat": "grass", "group": "brush-footed butterfly", "hab": "meadows and open fields", "habKey": "meadow", "diet": "flower nectar", "art": "meadow", "trait": "One of the most widespread butterflies on Earth, it migrates across whole continents."}, "mourning-cloak": {"name": "Mourning cloak", "cat": "grass", "group": "brush-footed butterfly", "hab": "forests and woodlands", "habKey": "forest", "diet": "flower nectar", "art": "grassland", "trait": "It survives winter as an adult and can be seen flying on warm late-winter days."}, "red-admiral": {"name": "Red admiral", "cat": "grass", "group": "brush-footed butterfly", "hab": "forest edges and clearings", "habKey": "edge", "diet": "flower nectar", "art": "grassland", "trait": "A fast, territorial butterfly crossed by bold red-orange bands on dark wings."}, "great-spangled-fritillary": {"name": "Great spangled fritillary", "cat": "insect", "group": "fritillary butterfly", "hab": "meadows and open fields", "habKey": "meadow", "diet": "flower nectar", "art": "butterfly", "trait": "Orange above and spangled with silver below, its caterpillars eat only violets."}, "cecropia-moth": {"name": "Cecropia moth", "cat": "insect", "group": "giant silk moth", "hab": "forests and woodlands", "habKey": "forest", "diet": "leaves and foliage", "art": "butterfly", "trait": "North America's largest native moth, with a wingspan as wide as a human hand."}, "polyphemus-moth": {"name": "Polyphemus moth", "cat": "insect", "group": "giant silk moth", "hab": "forests and woodlands", "habKey": "forest", "diet": "leaves and foliage", "art": "butterfly", "trait": "A big tan silk moth named for the single large eyespot on each hindwing."}, "io-moth": {"name": "Io moth", "cat": "insect", "group": "silk moth", "hab": "forest edges and clearings", "habKey": "edge", "diet": "leaves and foliage", "art": "butterfly", "trait": "Its yellow wings hide startling eyespots, and its caterpillar carries stinging spines."}, "hummingbird-clearwing": {"name": "Hummingbird clearwing", "cat": "insect", "group": "sphinx moth (insect)", "hab": "meadows and open fields", "habKey": "meadow", "diet": "flower nectar", "art": "butterfly", "trait": "A day-flying moth that hovers at flowers and beats its wings like a tiny hummingbird."}, "eastern-hercules-beetle": {"name": "Eastern Hercules beetle", "cat": "insect", "group": "rhinoceros beetle", "hab": "forests and woodlands", "habKey": "forest", "diet": "fruit and berries", "art": "butterfly", "trait": "A giant beetle whose horned males wrestle one another over sap and mates."}, "dogbane-beetle": {"name": "Dogbane beetle", "cat": "insect", "group": "leaf beetle (insect)", "hab": "meadows and open fields", "habKey": "meadow", "diet": "leaves and foliage", "art": "butterfly", "trait": "Its shell shifts through gold, green and copper like polished, living metal."}, "eyed-click-beetle": {"name": "Eastern eyed click beetle", "cat": "insect", "group": "click beetle (insect)", "hab": "forests and woodlands", "habKey": "forest", "diet": "leaves and foliage", "art": "butterfly", "trait": "Two big eyespots mark its back, and it snaps loudly to flip itself upright when overturned."}, "six-spotted-tiger-beetle": {"name": "Six-spotted tiger beetle", "cat": "insect", "group": "tiger beetle (insect)", "hab": "forests and woodlands", "habKey": "forest", "diet": "insects and other small invertebrates", "art": "butterfly", "trait": "A fast, metallic-green hunter that sprints down sunny forest paths after prey."}, "eastern-carpenter-bee": {"name": "Eastern carpenter bee", "cat": "insect", "group": "carpenter bee", "hab": "towns, parks and gardens", "habKey": "urban", "diet": "flower nectar", "art": "butterfly", "trait": "A large bee that bores round tunnels into wood; the hovering males have no sting at all."}, "bald-faced-hornet": {"name": "Bald-faced hornet", "cat": "insect", "group": "hornet (insect)", "hab": "forest edges and clearings", "habKey": "edge", "diet": "insects and other small invertebrates", "art": "butterfly", "trait": "Really a yellowjacket, it builds a big gray paper nest shaped like a hanging teardrop."}, "eastern-yellowjacket": {"name": "Eastern yellowjacket", "cat": "insect", "group": "yellowjacket wasp", "hab": "forest edges and clearings", "habKey": "edge", "diet": "a wide range of plant and animal foods", "art": "butterfly", "trait": "A ground-nesting wasp that crashes late-summer picnics for sweets and meats."}, "common-whitetail": {"name": "Common whitetail", "cat": "insect", "group": "dragonfly (insect)", "hab": "lakes and ponds", "habKey": "lake", "diet": "insects and other small invertebrates", "art": "butterfly", "trait": "Males guard ponds by flashing a chalky-white abdomen at rival males."}, "ebony-jewelwing": {"name": "Ebony jewelwing", "cat": "insect", "group": "damselfly (insect)", "hab": "rivers and streams", "habKey": "river", "diet": "insects and other small invertebrates", "art": "butterfly", "trait": "A streamside damselfly with inky black wings and a body that glints metallic green."}, "field-cricket": {"name": "Field cricket", "cat": "insect", "group": "cricket (insect)", "hab": "grasslands and prairies", "habKey": "grass", "diet": "a wide range of plant and animal foods", "art": "butterfly", "trait": "The familiar chirp of late summer is made by males rubbing their wings together."}, "bold-jumper": {"name": "Bold jumping spider", "cat": "arachnid", "group": "jumping spider (arachnid)", "hab": "forest edges and clearings", "habKey": "edge", "diet": "insects and other small invertebrates", "art": "fern", "trait": "A small, fuzzy spider with huge forward eyes that pounces on prey instead of spinning a web."}, "eastern-harvestman": {"name": "Eastern harvestman", "cat": "arachnid", "group": "harvestman (arachnid)", "hab": "forests and woodlands", "habKey": "forest", "diet": "insects and other small invertebrates", "art": "fern", "trait": "Often called daddy-longlegs, it is not a true spider and makes neither silk nor venom."}, "southern-black-widow": {"name": "Southern black widow", "cat": "arachnid", "group": "widow spider (arachnid)", "hab": "forest edges and clearings", "habKey": "edge", "diet": "insects and other small invertebrates", "art": "fern", "trait": "A glossy black spider marked with a red hourglass; its venom is potent but bites are rare."}, "brown-recluse": {"name": "Brown recluse", "cat": "arachnid", "group": "recluse spider (arachnid)", "hab": "towns, parks and gardens", "habKey": "urban", "diet": "insects and other small invertebrates", "art": "fern", "trait": "A shy spider with a violin-shaped mark that hides in quiet, undisturbed corners."}, "gabbro": {"name": "Gabbro", "cat": "rock", "group": "coarse igneous rock", "hab": "", "habKey": null, "diet": "", "art": "mineral", "trait": "It is the deep-earth cousin of basalt, sharing its minerals but growing much larger crystals."}, "rhyolite": {"name": "Rhyolite", "cat": "rock", "group": "fine igneous rock", "hab": "", "habKey": null, "diet": "", "art": "mineral", "trait": "Pale and packed with tiny crystals, it erupts from some of the most explosive volcanoes."}, "andesite": {"name": "Andesite", "cat": "rock", "group": "volcanic igneous rock", "hab": "", "habKey": null, "diet": "", "art": "mineral", "trait": "A medium-gray lava rock typical of the chain of volcanoes ringing the Pacific."}, "chert": {"name": "Chert", "cat": "rock", "group": "hard sedimentary rock", "hab": "", "habKey": null, "diet": "", "art": "mineral", "trait": "It breaks with razor edges, so early people chipped it (as flint) into arrowheads and blades."}, "breccia": {"name": "Breccia", "cat": "rock", "group": "sedimentary rock", "hab": "", "habKey": null, "diet": "", "art": "mineral", "trait": "Its pieces are sharp and angular, a sign they were buried before travel could wear them smooth."}, "schist": {"name": "Schist", "cat": "rock", "group": "metamorphic rock", "hab": "", "habKey": null, "diet": "", "art": "mineral", "trait": "It sparkles with mica and splits into wavy, glittering sheets."}, "garnet": {"name": "Garnet", "cat": "mineral", "group": "mineral", "hab": "", "habKey": null, "diet": "", "art": "mineral", "trait": "Hard and sharp, crushed garnet is used as sandpaper grit and in waterjet cutters."}, "magnetite": {"name": "Magnetite", "cat": "mineral", "group": "iron mineral", "hab": "", "habKey": null, "diet": "", "art": "mineral", "trait": "A single piece can pull a compass needle off course; a magnetized lump is called lodestone."}, "galena": {"name": "Galena", "cat": "mineral", "group": "mineral", "hab": "", "habKey": null, "diet": "", "art": "mineral", "trait": "Heavy and metallic gray, it cleaves into neat little cubes."}, "talc": {"name": "Talc", "cat": "mineral", "group": "soft mineral", "hab": "", "habKey": null, "diet": "", "art": "mineral", "trait": "So soft you can scratch it with a fingernail, it is ground into talcum powder."}, "graphite": {"name": "Graphite", "cat": "mineral", "group": "mineral", "hab": "", "habKey": null, "diet": "", "art": "mineral", "trait": "Gray and greasy to the touch, it is the 'lead' in pencils and even conducts electricity."}, "brachiopod": {"name": "Brachiopod", "cat": "fossil", "group": "fossil shell", "hab": "", "habKey": null, "diet": "", "art": "fossil", "trait": "Their fossils are among the most common finds in ancient sea-floor rocks."}, "crinoid": {"name": "Crinoid", "cat": "fossil", "group": "fossil sea lily", "hab": "", "habKey": null, "diet": "", "art": "fossil", "trait": "They left button- and stem-shaped fossils stacked like tiny stone poker chips."}, "fossil-shark-tooth": {"name": "Fossil shark tooth", "cat": "fossil", "group": "fossil tooth", "hab": "", "habKey": null, "diet": "", "art": "fossil", "trait": "Because a shark's skeleton is soft cartilage, its hard teeth are the part most often fossilized."}, "fossil-coral": {"name": "Fossil coral", "cat": "fossil", "group": "reef fossil", "hab": "", "habKey": null, "diet": "", "art": "fossil", "trait": "Ancient reef corals left honeycomb and chain-link patterns preserved in limestone."}};
